INSERT INTO books (title, author, cover_url, description, genre, page_count, isbn, amazon_data, goodreads_data)
VALUES
  ('Sapiens: A Brief History of Humankind', 'Yuval Noah Harari', 'https://m.media-amazon.com/images/I/716E6dQ4BXL._SL1500_.jpg', 'From a renowned historian comes a groundbreaking narrative of humanity’s creation and evolution—a #1 international bestseller—that explores the ways in which biology and history have defined us and enhanced our understanding of what it means to be “human.” One hundred thousand years ago, at least six different species of humans inhabited Earth. Yet today there is only one—homo sapiens. What happened to the others? And what may happen to us? Most books about the history of humanity pursue either a historical or a biological approach, but Dr. Yuval Noah Harari breaks the mold with this highly original book that begins about 70,000 years ago with the appearance of modern cognition. From examining the role evolving humans have played in the global ecosystem to charting the rise of empires, Sapiens integrates history and science to reconsider accepted narratives, connect past developments with contemporary concerns, and examine specific events within the context of larger ideas. Dr. Harari ', 'History', 512, '9780062316097', '{"title":"Sapiens: A Brief History of Humankind – The #1 New York Times Bestseller Exploring Evolution and Ancient Socieities","author":"Yuval Noah Harari","description":"#1 New York Times Bestseller • New York Times Readers’ Pick: Top 100 Books of the 21st Century • The Summer Reading Pick for President Barack Obama and Bill Gates\nOfficial U.S. edition with full color illustrations throughout.\nFrom renowned historian Yuval Noah Harari comes a landmark work of big history, a groundbreaking narrative of humanity’s creation and evolution―a #1 international bestseller―that explores the ways in which biology and history have defined us and enhanced our understanding of what it means to be “human.”\nOne hundred thousand years ago, at least six different species of humans inhabited Earth. Yet today there is only one―homo sapiens. What happened to the others? And what may happen to us?\nMost books about the history of humanity pursue either a historical or a biological approach, but Dr. Yuval Noah Harari breaks the mold with this highly original book that begins about 70,000 years ago with the Cognitive Revolution and the appearance of modern cognition. From examining the story of human evolution in the global ecosystem to charting the rise of empires, Sapiens integrates history and science to reconsider accepted narratives, connect past developments with contemporary concerns, and examine specific events within the context of larger ideas.\nDr. Harari also compels us to look ahead, because in the wake of the Scientific Revolution, humans have begun to bend laws of natural selection that have governed life for the past four billion years. We are acquiring the ability to design not only the world around us, but also ourselves. Where is this leading us, and what do we want to become?\nFeaturing 27 photographs, 6 maps, and 25 illustrations/diagrams, this provocative and insightful work is sure to spark debate and is essential reading for aficionados of Jared Diamond, James Gleick, Matt Ridley, Robert Wright, and Sharon Moalem.\nThis ambitious account of our species answers the most fundamental questions of our history:\nA Brief History of Humankind: How did an insignificant ape become the ruler of the planet, capable of splitting the atom, walking on the Moon, and engineering the code of life?\nA Brief History of Humankind: How did an insignificant ape become the ruler of the planet, capable of splitting the atom, walking on the Moon, and engineering the code of life?\nThe Power of Myth: Discover the secret of our success―the unique ability to believe in collective fictions like gods, nations, money, and human rights that allow for large-scale cooperation.\nThe Power of Myth: Discover the secret of our success―the unique ability to believe in collective fictions like gods, nations, money, and human rights that allow for large-scale cooperation.\nIntegrating History and Science: Journey through the Cognitive, Agricultural, and Scientific Revolutions and explore how they shaped not just our societies, but our very identities.\nIntegrating History and Science: Journey through the Cognitive, Agricultural, and Scientific Revolutions and explore how they shaped not just our societies, but our very identities.\nThe Question of Happiness: With all our power and knowledge, are we any happier than our ancient ancestors? Harari challenges everything we think we know about what it means to be human.\nThe Question of Happiness: With all our power and knowledge, are we any happier than our ancient ancestors? Harari challenges everything we think we know about what it means to be human.","asin":"0062316095","isbn13":"9780062316097","price":"$15.98","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.72,"4star":0.21,"3star":0.05,"2star":0.01,"1star":0.01},"reviewsCount":133060,"thumbnailImage":"https://m.media-amazon.com/images/I/716E6dQ4BXL._SL1500_.jpg","url":"https://www.amazon.com/dp/0062316095","genre":"Military","publisher":"Harper","pubDate":"February 10, 2015","language":"English","edition":"Illustrated","pageCount":464,"bestsellerRanks":[{"rank":7156,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Physics of Time (Books)","url":"https://www.amazon.com/gp/bestsellers/books/14598/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Evolution (Books)","url":"https://www.amazon.com/gp/bestsellers/books/13824/ref=pd_zg_hrsr_books"},{"rank":1,"category":"General Anthropology","url":"https://www.amazon.com/gp/bestsellers/books/11237/ref=pd_zg_hrsr_books"}],"inStockText":"Only 1 left in stock - order soon.  Only 1 left in stock - order soon.","delivery":"Friday, July 3","aiSummary":"Customers find this history book engaging and thought-provoking, providing a carefully researched and detailed overview of human history. The writing style is accessible and entertaining, making it a hard-to-stop read, while the narrative presents a sweeping historical account. The book receives positive feedback for its intellectual depth, with one customer noting its highly readable scientific content. While some customers find it very factual, others point out that it''s not always factually correct.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book engaging and entertaining, describing it as a must-read.","reviews":["This is a great book for those that want to consider the biology of humans alongside questions of ethics, religion, philosophy, and overall meaning...","A great read. Thoroughly engrossing and very well explained. It certainly helps to bring some perspective to human life. A must read for all Sapiens.","Really well written and interesting. I was especially fascinated by the blending of science and pre-history. Gets a little morbid at the conclusion"]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking, describing it as an insightful and educational philosophical treatise that provides perspective on human history.","reviews":["Although I do find this book to be thought provoking, hence the 3rd star, it seems the author has only used historical facts that support his premise...","Insightful, scholarly and thought provoking history of our species with profound implications for its future. Carve out time to read this masterpiece.","...Well written and easy to read with lots of interesting points. Very thought provoking - although not all of his claims are well enough backed for me..."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book informative and well-researched, with detailed content that is carefully documented. One customer describes it as a highly readable overview of the science.","reviews":["One of the most interesting, informative, and ease to read books I have read in a long time.","Fantastic book! Very informative and thought-provoking. Loved it!","The book is educational, rational, well researched, objective, and well annotated. Brilliant presentation of the development of Homo Sapiens."]},{"name":"Writing quality","sentiment":"positive","text":"Customers praise the writing quality of the book, describing it as excellently and superbly written, with accessible and witty prose.","reviews":["...Should be required reading in high school. Well written, amazing research and breadth of topic, which should concern every human (as in Homo sapien)....","Very well written, entertaining, and very interesting point of view of how we have progress and evolved as human beings and the consequences to our...","A well written book. The subject matter for each section flows fluidly. Well thought out. I had to rethink many ideas I took fro granted in the past"]},{"name":"Readability","sentiment":"positive","text":"Customers find the book remarkably clear and easy to understand, though they note it is not a light read and can be hard to put down.","reviews":["Rich perspectives on complex issues, yet, easy to read. The author puts together an imence number of facts, with references, wihout losing oversight....","Wonderful journey through the world that shaped mankind. A fun, easy read. Thought provoking, occasionally disturbing and often mind blowing.","I believe this is a compendium of a series of lectures , and is a clear, easily understandable, and charming book about the development of our..."]},{"name":"Story","sentiment":"positive","text":"Customers appreciate the book''s story, describing it as a fascinating journey and sweeping historical narrative.","reviews":["this book is a great story connecting many centuries of our history into one bigger picture, providing comprehensive theory to why we are who we are....","An excellent summary, written informally enough to read like a novel, but very insightful and pecise nonetheless....","This book issued plenty of examples and stories that help you visualize history of mankind and contextualize massive concepts. I highly recommend it."]},{"name":"Thoughtful","sentiment":"positive","text":"Customers appreciate the book''s thoughtful approach, noting its tremendous intellectual depth and well-considered content.","reviews":["...It is effectively written with thoughtful, creative perspectives by an intelligent historian member of our species in a manner that held my interest.","This is an intelligent, highly informed look at humankind and our ways which seems to present the distant perspective an alien life form might have....","The book is a college education in history, anthropology, government, philosophy and more- from cave-paintings to empires. And it''s fun to read!"]},{"name":"Accuracy","sentiment":"mixed","text":"Customers have mixed opinions about the book''s accuracy, with some finding it very factual while others consider it very misleading and discredited theories.","reviews":["...are also discussions about the rise of agriculture, religion, and science and how these factors have and are continuing to change the direction in...","...; however, my Ph.D. science friends thought it too far-flung and unscientific. I say \"go for it\".","Its title says it is a history but it reads more like philosophical, scientific, psychological speculation (perhaps at least partly fiction)...."]}],"features":[]}'::jsonb, '{"title":"Sapiens: A Brief History of Humankind","author":"Yuval Noah Harari","description":"From a renowned historian comes a groundbreaking narrative of humanity’s creation and evolution—a #1 international bestseller—that explores the ways in which biology and history have defined us and enhanced our understanding of what it means to be “human.” One hundred thousand years ago, at least six different species of humans inhabited Earth. Yet today there is only one—homo sapiens. What happened to the others? And what may happen to us? Most books about the history of humanity pursue either a historical or a biological approach, but Dr. Yuval Noah Harari breaks the mold with this highly original book that begins about 70,000 years ago with the appearance of modern cognition. From examining the role evolving humans have played in the global ecosystem to charting the rise of empires, Sapiens integrates history and science to reconsider accepted narratives, connect past developments with contemporary concerns, and examine specific events within the context of larger ideas. Dr. Harari also compels us to look ahead, because over the last few decades humans have begun to bend laws of natural selection that have governed life for the past four billion years. We are acquiring the ability to design not only the world around us, but also ourselves. Where is this leading us, and what do we want to become? Featuring 27 photographs, 6 maps, and 25 illustrations/diagrams, this provocative and insightful work is sure to spark debate and is essential reading for aficionados of Jared Diamond, James Gleick, Matt Ridley, Robert Wright, and Sharon Moalem.","genres":["Nonfiction","History","Science","Audiobook","Philosophy","Anthropology","Psychology","Sociology","Historical","Evolution"],"averageRating":4.33,"ratingsCount":1305262,"ratingsDistribution":{"1":710544,"2":392675,"3":141681,"4":38030,"5":22332},"pages":512,"isbn13":"","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1703329310i/23692271.jpg","publishedAt":"2015-01-01","series":{"name":"Homo","position":"1","url":"https://www.goodreads.com/series/432659-homo"},"awards":[],"url":"https://www.goodreads.com/book/show/23692271-sapiens","reviews":[]}'::jsonb),
  ('Atomic Habits: An Easy & Proven Way to Build Good Habits & Break Bad Ones', 'James Clear', 'https://m.media-amazon.com/images/I/81kg51XRc1L._SL1500_.jpg', 'No matter your goals, Atomic Habits offers a proven framework for improving—every day. James Clear, one of the world''s leading experts on habit formation, reveals practical strategies that will teach you exactly how to form good habits, break bad ones, and master the tiny behaviors that lead to remarkable results. If you''re having trouble changing your habits, the problem isn''t you. The problem is your system. Bad habits repeat themselves again and again not because you don''t want to change, but because you have the wrong system for change. You do not rise to the level of your goals. You fall to the level of your systems. Here, you''ll get a proven system that can take you to new heights. Clear is known for his ability to distill complex topics into simple behaviors that can be easily applied to daily life and work. Here, he draws on the most proven ideas from biology, psychology, and neuroscience to create an easy-to-understand guide for making good habits inevitable and bad habits imp', 'Self-help', 319, '9780735211292', '{"title":"Atomic Habits: An Easy & Proven Way to Build Good Habits & Break Bad Ones","author":"James Clear","description":"The #1 New York Times bestseller.Over 25 million copies sold!Translated into 60+ languages!Tiny Changes, Remarkable ResultsNo matter your goals, Atomic Habits offers a proven framework for improving--every day. James Clear, one of the world''s leading experts on habit formation, reveals practical strategies that will teach you exactly how to form good habits, break bad ones, and master the tiny behaviors that lead to remarkable results.If you''re having trouble changing your habits, the problem isn''t you. The problem is your system. Bad habits repeat themselves again and again not because you don''t want to change, but because you have the wrong system for change. You do not rise to the level of your goals. You fall to the level of your systems. Here, you''ll get a proven system that can take you to new heights.Clear is known for his ability to distill complex topics into simple behaviors that can be easily applied to daily life and work. Here, he draws on the most proven ideas from biology, psychology, and neuroscience to create an easy-to-understand guide for making good habits inevitable and bad habits impossible. Along the way, readers will be inspired and entertained with true stories from Olympic gold medalists, award-winning artists, business leaders, life-saving physicians, and star comedians who have used the science of small habits to master their craft and vault to the top of their field.Learn how to:\nmake time for new habits (even when life gets crazy);\nmake time for new habits (even when life gets crazy);\novercome a lack of motivation and willpower;\novercome a lack of motivation and willpower;\ndesign your environment to make success easier;\ndesign your environment to make success easier;\nget back on track when you fall off course;\nget back on track when you fall off course;\n...and much more.Atomic Habits will reshape the way you think about progress and success, and give you the tools and strategies you need to transform your habits--whether you are a team looking to win a championship, an organization hoping to redefine an industry, or simply an individual who wishes to quit smoking, lose weight, reduce stress, or achieve any other goal.","asin":"0735211299","isbn13":"9780735211292","price":"$18","listPrice":null,"stars":4.8,"starsBreakdown":{"5star":0.84,"4star":0.13,"3star":0.03,"2star":0,"1star":0},"reviewsCount":148665,"thumbnailImage":"https://m.media-amazon.com/images/I/81kg51XRc1L._SL1500_.jpg","url":"https://www.amazon.com/dp/0735211299","genre":"Social Psychology & Interactions","publisher":"Avery","pubDate":"October 16, 2018","language":"English","edition":"First Edition","pageCount":320,"bestsellerRanks":[{"rank":50,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Parenting (Books)","url":"https://www.amazon.com/gp/bestsellers/books/11401/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Popular Social Psychology & Interactions","url":"https://www.amazon.com/gp/bestsellers/books/11223/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Business & Money (Books)","url":"https://www.amazon.com/gp/bestsellers/books/3/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book life-changing and full of practical strategies, with clear explanations of habit formation backed by research. The book takes readers step-by-step through the process, providing numerous real-life examples to illustrate its points. Customers appreciate its straightforward approach, making it a quick and easy read.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book enjoyable and life-changing, describing it as a must-read for everyone.","reviews":["Great book that lays out an easy formula to follow to develop good habits and remove bad ones. Easy read, but also setup to be a good reference book.","Great read, actionable templates and good flow/direction. Many additional resources available. Very clear and easy to follow. Logical layout of ideas","Good book, lead you to think about your habits, and what you have done, and then to explain why they are so, and then to tell you in detail how all..."]},{"name":"Practical","sentiment":"positive","text":"Customers find the book practical and helpful, providing great advice and useful strategies for building good habits and breaking bad ones.","reviews":["This is no rah rah, you can do it manifesto. It’s practical and logical, and while you may know all of these things already, having them broken down...","This book is so clear and helpful. I have enjoyed James Clear’s anecdotes and explanations for exactly how habits are formed, good ones and bad ones!...","My favorite book in a long time, and I read ALOT of non-fiction. Useful, smart, easy to understand and follow/implement. I plan to re-read it soon."]},{"name":"Habit formation","sentiment":"positive","text":"Customers praise the book for its comprehensive approach to habit formation, explaining the science behind it and providing tools to start and stop behaviors.","reviews":["Easily the best book on habits I have ever read!! I have read a lot of self-help books and this is by far one of my top 10!...","...it to everyone who want to build stable and good foundations, good habits!","I bought Atomic Habits: An Easy & Proven Way to Build Good Habits & Break Bad Ones by James Clear because it had been recommended to me so very many..."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book informative, praising its insightful information and great research, with one customer noting it provides a new perspective.","reviews":["...While many of these books are enjoyable and insightful, once you get to the end, you are left scratching your head saying “How do I implement what I...","I absolutely love this book & it has been extremely helpful & informative in getting me out of a rut & all bad habits that I formed since Covid,...","Very informative and full of great tips. Helping me to rethink the habits I have, what stops me from changing them, and how to do things differently."]},{"name":"Simplicity","sentiment":"positive","text":"Customers appreciate the book''s straightforward approach, as it takes them step by step through the science of habits and provides an immediately implementable plan.","reviews":["...10-20k hours into work on behavior change, I really appreciated the simple, proven, and fact-based approach James has taken in this outstanding book....","...conditions to delevop good habits like making them obvious, attractive, easy and satisfying but maybe most important to be aware that at some point...","James Clear, author of Atomic Habits has written a book which is easy to understand, practical in its application and powerful in that applying the..."]},{"name":"Clarity","sentiment":"positive","text":"Customers praise the book''s clarity, finding it brilliantly explained and very straight to the point, with concepts that are simple yet profound.","reviews":["A clear and highly practical book that breaks down behavior change into small, manageable steps that are easy to understand and apply in daily life....","The book was short, simple, concise and practical. The strategies and tactics are easily understood and easily applied. Highly recommend.","...And his ability to provide science-based, understandable and practical advice throughout the book is what makes this book so useful for anyone who..."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book easy to read and understand, describing it as a quick and good read.","reviews":["Really great book. Very informative and easy to read. You will find a lot of reasons for why you do something and why you don''t. Makes a lot of sense.","An easy read, with great examples. Tools are provided to help identify current habits, how to layer on the good ones and eliminate the bad ones....","...it is very easy to read and apply to your everyday living. He give you powerful tips, encourage good habits, and inspiring true stories...."]},{"name":"Examples","sentiment":"positive","text":"Customers appreciate the book''s variety of real-life examples that make the concepts clear and implementable.","reviews":["Engaging stories and examples. Convenient summary of points at the end of each short chapter. The small (atom sized) changes in routine really work!...","...Great ideas and great suggestions for becoming the person you truly want to be and ridding yourself of bad habits that keep you down.","Very entertaining. Great examples. Easy to read. The habit building (or habit breaking) method is broken down...."]}],"features":[]}'::jsonb, '{"title":"Atomic Habits: An Easy & Proven Way to Build Good Habits & Break Bad Ones","author":"James Clear","description":"No matter your goals, Atomic Habits offers a proven framework for improving—every day. James Clear, one of the world''s leading experts on habit formation, reveals practical strategies that will teach you exactly how to form good habits, break bad ones, and master the tiny behaviors that lead to remarkable results. If you''re having trouble changing your habits, the problem isn''t you. The problem is your system. Bad habits repeat themselves again and again not because you don''t want to change, but because you have the wrong system for change. You do not rise to the level of your goals. You fall to the level of your systems. Here, you''ll get a proven system that can take you to new heights. Clear is known for his ability to distill complex topics into simple behaviors that can be easily applied to daily life and work. Here, he draws on the most proven ideas from biology, psychology, and neuroscience to create an easy-to-understand guide for making good habits inevitable and bad habits impossible. Along the way, readers will be inspired and entertained with true stories from Olympic gold medalists, award-winning artists, business leaders, life-saving physicians, and star comedians who have used the science of small habits to master their craft and vault to the top of their field. Learn how to: - Make time for new habits (even when life gets crazy); - Overcome a lack of motivation and willpower; - Design your environment to make success easier; - Get back on track when you fall off course; ...and much more. Atomic Habits will reshape the way you think about progress and success, and give you the tools and strategies you need to transform your habits--whether you are a team looking to win a championship, an organization hoping to redefine an industry, or simply an individual who wishes to quit smoking, lose weight, reduce stress, or achieve any other goal.","genres":["Self Help","Nonfiction","Psychology","Audiobook","Personal Development","Productivity","Business","Personal Growth","Leadership","Health"],"averageRating":4.31,"ratingsCount":1381694,"ratingsDistribution":{"1":709445,"2":455848,"3":167752,"4":34509,"5":14140},"pages":319,"isbn13":"","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1655988385i/40121378.jpg","publishedAt":"2018-10-16","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/40121378-atomic-habits","reviews":[]}'::jsonb),
  ('Thinking, Fast and Slow', 'Daniel Kahneman', 'https://m.media-amazon.com/images/I/61fdrEuPJwL._SL1500_.jpg', 'In the highly anticipated Thinking, Fast and Slow, Kahneman takes us on a groundbreaking tour of the mind and explains the two systems that drive the way we think. System 1 is fast, intuitive, and emotional; System 2 is slower, more deliberative, and more logical. Kahneman exposes the extraordinary capabilities—and also the faults and biases—of fast thinking, and reveals the pervasive influence of intuitive impressions on our thoughts and behavior. The impact of loss aversion and overconfidence on corporate strategies, the difficulties of predicting what will make us happy in the future, the challenges of properly framing risks at work and at home, the profound effect of cognitive biases on everything from playing the stock market to planning the next vacation—each of these can be understood only by knowing how the two systems work together to shape our judgments and decisions. Engaging the reader in a lively conversation about how we think, Kahneman reveals where we can and cannot tru', 'Psychology', 499, '9780374275631', '{"title":"Thinking, Fast and Slow","author":"Daniel Kahneman","description":"*Major New York Times Bestseller*More than 2.6 million copies sold*One of The New York Times Book Review''s ten best books of the year*Selected by The Wall Street Journal as one of the best nonfiction books of the year*Presidential Medal of Freedom Recipient*Daniel Kahneman''s work with Amos Tversky is the subject of Michael Lewis''s best-selling The Undoing Project: A Friendship That Changed Our MindsIn his mega bestseller, Thinking, Fast and Slow, Daniel Kahneman, world-famous psychologist and winner of the Nobel Prize in Economics, takes us on a groundbreaking tour of the mind and explains the two systems that drive the way we think. System 1 is fast, intuitive, and emotional; System 2 is slower, more deliberative, and more logical. The impact of overconfidence on corporate strategies, the difficulties of predicting what will make us happy in the future, the profound effect of cognitive biases on everything from playing the stock market to planning our next vacation―each of these can be understood only by knowing how the two systems shape our judgments and decisions.Engaging the reader in a lively conversation about how we think, Kahneman reveals where we can and cannot trust our intuitions and how we can tap into the benefits of slow thinking. He offers practical and enlightening insights into how choices are made in both our business and our personal lives―and how we can use different techniques to guard against the mental glitches that often get us into trouble. Topping bestseller lists for almost ten years, Thinking, Fast and Slow is a contemporary classic, an essential book that has changed the lives of millions of readers.","asin":"0374533555","isbn13":"9780374533557","price":"$11.42","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.72,"4star":0.19,"3star":0.07,"2star":0.01,"1star":0.01},"reviewsCount":48329,"thumbnailImage":"https://m.media-amazon.com/images/I/61fdrEuPJwL._SL1500_.jpg","url":"https://www.amazon.com/dp/0374533555","genre":"Decision-Making & Problem Solving","publisher":"Farrar, Straus and Giroux","pubDate":"April 2, 2013","language":"English","edition":"First Edition","pageCount":512,"bestsellerRanks":[{"rank":695,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Decision-Making & Problem Solving","url":"https://www.amazon.com/gp/bestsellers/books/2679/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Business Decision Making","url":"https://www.amazon.com/gp/bestsellers/books/10020716011/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Medical Cognitive Psychology","url":"https://www.amazon.com/gp/bestsellers/books/15811861/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book highly informative and engaging, with amazing research and many insights about the mind. The writing quality is excellent, with one customer noting it''s written for a lay audience, and they consider it worth all 500+ pages. The concepts are easier to understand, and customers say it forces them to think differently. While some find it readable, others describe it as a hard read, and the pacing receives mixed reviews with several customers finding it slow.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book engaging and life-changing, describing it as a marvelous and interesting read that is absolutely essential to read.","reviews":["...got into some statistical and philosophical nuances, but overall a great book and important read for anyone wanting to understand how people think.","Great read that may seem difficult at first, but the book itself is a staple for anyone looking to improve their overall quality of life and also...","Excellent book Kind of long, but nevertheless fascinating. Pioneer in neuroeconomics (together with Amos T). Introduced the notion of cognitive bias...."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book highly informative and insightful, praising its amazing research and valuable perspective.","reviews":["Excelent book! Inteligent. Intriguing. Insightful. Finally, a great book to understand the human behavior in economics and finance....","...Informative and useful on a personal level as well. Reading the book I was often stopped in my tracks by its stunning revelations and insights....","Excellent book, very insightful. Viewing the thinking process in a whole new way now. Highly recommend!"]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking, providing many insights about the mind and forcing readers to think differently.","reviews":["...The book had the potential to be useful and thought provoking by delving into issues like racism and sexism, but the author seemed to shy away from...","Great read. Very thought provoking and engaging. It''s interesting to think about how we react with our world and what influences our decisions.","This was a fascinating look at decision making, both intuitive and thoughtful. He explained the process by which we can make such bad decisions...."]},{"name":"Writing quality","sentiment":"positive","text":"Customers praise the writing quality of the book, noting it is excellently written by a tremendously gifted author who is very knowledgeable in his field.","reviews":["A very dense book. But well written. The first third could be a book on its own. Then it takes those concepts and drives deeper. Then deeper still....","...Is there a way to rein our mental horses? Very well written, engaging, based on solid research, spiced with a bit of irony book on ultimately...","...The content is as described. It is well-written and compelling without being technical--you see the cathedral without the scaffolding...."]},{"name":"Value for money","sentiment":"positive","text":"Customers find the book extremely valuable, noting that it''s worth all 500+ pages and well worth the effort to get through.","reviews":["...It’s a serious read but worth the effort. Now that I’ve read Thinking Fast and Slow, I gotta do some writing of my own....","This book takes a bit of time and effort but it is without a doubt worth it. Learning about how something works is the best way to improve.","Great book, worth the read for anyone wanting better insight into decision making for business or personal reasons. No hesitation."]},{"name":"Complexity","sentiment":"positive","text":"Customers find the book''s concepts easier to understand and appreciate its readable explanations, noting that it helps with decision making. One customer mentions it is particularly accessible for non-statisticians.","reviews":["He nails the material, but in a modest way that is easy to understand....","...is able to put out his information in such great stories that are easy to follow and digest, and you''ll never be able to think the same way again.","Excellent content and an easy, seamless read! This book is great for anyone who wants to gain insight on how we make decisions...."]},{"name":"Readability","sentiment":"mixed","text":"Customers have mixed opinions about the book''s readability, with some finding it clear and substantial, while others describe it as hard to get through and painful to read.","reviews":["...This book is easy to read and strikes an impressive balance; it preserves much of the evidence and logic found in his academic works, but presents...","Not an easy read but compelling and incredibly revealing. Daniel Kahneman''s research is painstaking and, where he has doubts - honest....","...It breaks down how we think in a way that is clear and eye opening, showing the difference between fast instinctive thinking and slower more..."]},{"name":"Pacing","sentiment":"mixed","text":"Customers have mixed opinions about the pacing of the book, with several noting it is slow and takes time to read, while one customer found the content presented at a nice pace.","reviews":["...it''s dense though, not a quick read, or a page-turner. but there is so much to learn....","Thinking, Fast and Slow provides valuable insight into how the human (your) mind works through complex decision making....","...Warning, it is not a fast read like those written by Malcolm Gladwell, Daniel Pink, or Charles Duhigg...."]}],"features":[]}'::jsonb, '{"title":"Thinking, Fast and Slow","author":"Daniel Kahneman","description":"In the highly anticipated Thinking, Fast and Slow, Kahneman takes us on a groundbreaking tour of the mind and explains the two systems that drive the way we think. System 1 is fast, intuitive, and emotional; System 2 is slower, more deliberative, and more logical. Kahneman exposes the extraordinary capabilities—and also the faults and biases—of fast thinking, and reveals the pervasive influence of intuitive impressions on our thoughts and behavior. The impact of loss aversion and overconfidence on corporate strategies, the difficulties of predicting what will make us happy in the future, the challenges of properly framing risks at work and at home, the profound effect of cognitive biases on everything from playing the stock market to planning the next vacation—each of these can be understood only by knowing how the two systems work together to shape our judgments and decisions. Engaging the reader in a lively conversation about how we think, Kahneman reveals where we can and cannot trust our intuitions and how we can tap into the benefits of slow thinking. He offers practical and enlightening insights into how choices are made in both our business and our personal lives—and how we can use different techniques to guard against the mental glitches that often get us into trouble. Thinking, Fast and Slow will transform the way you think about thinking.","genres":["Nonfiction","Psychology","Self Help","Science","Business","Economics","Personal Development","Philosophy","Audiobook","Leadership"],"averageRating":4.17,"ratingsCount":606905,"ratingsDistribution":{"1":281463,"2":194838,"3":93325,"4":24479,"5":12800},"pages":499,"isbn13":"9780374275631","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1317793965i/11468377.jpg","publishedAt":"2011-10-25","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/11468377-thinking-fast-and-slow","reviews":[]}'::jsonb),
  ('The Psychology of Money: Timeless Lessons on Wealth, Greed, and Happiness', 'Morgan Housel', 'https://m.media-amazon.com/images/I/81gC3mdNi5L._SL1500_.jpg', 'Alternate cover edition of ISBN 9780857197689. Doing well with money isn’t necessarily about what you know. It’s about how you behave. And behavior is hard to teach, even to really smart people. Money―investing, personal finance, and business decisions―is typically taught as a math-based field, where data and formulas tell us exactly what to do. But in the real world people don’t make financial decisions on a spreadsheet. They make them at the dinner table, or in a meeting room, where personal history, your own unique view of the world, ego, pride, marketing, and odd incentives are scrambled together. In The Psychology of Money, award-winning author Morgan Housel shares 19 short stories exploring the different ways people think about money and teaches you how to make better sense of one of life’s most important topics.', 'Business', 242, '9780857197689', '{"title":"The Psychology of Money: Timeless lessons on wealth, greed, and happiness","author":"Morgan Housel","description":"**OVER 10 MILLION COPIES SOLD AROUND THE WORLD… The Psychology of Money is the original bestselling classic from the author of the new book, The Art of Spending Money.**Doing well with money isn’t necessarily about what you know. It’s about how you behave. And behavior is hard to teach, even to really smart people.Money―investing, personal finance, and business decisions―is typically taught as a math-based field, where data and formulas tell us exactly what to do. But in the real world people don’t make financial decisions on a spreadsheet. They make them at the dinner table, or in a meeting room, where personal history, your own unique view of the world, ego, pride, marketing, and odd incentives are scrambled together.In The Psychology of Money, award-winning author Morgan Housel shares 19 short stories exploring the different ways people think about money and teaches you how to make better sense of one of life’s most important topics.","asin":"0857197681","isbn13":"9780857197689","price":"$10.99","listPrice":null,"stars":4.7,"starsBreakdown":{"5star":0.76,"4star":0.18,"3star":0.05,"2star":0.01,"1star":0},"reviewsCount":72274,"thumbnailImage":"https://m.media-amazon.com/images/I/81gC3mdNi5L._SL1500_.jpg","url":"https://www.amazon.com/dp/0857197681","genre":"Budgeting & Money Management","publisher":"Harriman House","pubDate":"September 8, 2020","language":"English","edition":"","pageCount":256,"bestsellerRanks":[{"rank":49,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Macroeconomics (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2596/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Occupational & Organizational Popular Psychology","url":"https://www.amazon.com/gp/bestsellers/books/11189/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Wealth Management (Books)","url":"https://www.amazon.com/gp/bestsellers/books/10020675011/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock","delivery":"Thursday, July 2","aiSummary":"Customers find this personal finance book enlightening and entertaining, with a conversational writing style that makes complex concepts feel straightforward. The book features relatable stories that explain investing, and customers appreciate how it changes their perspective on how money works. They praise its clarity, with one customer noting how the final chapter summarizes all concepts nicely, and find it easy to relate to and practice. Customers consider it worth the purchase, with one mentioning it saves more than its cost.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book informative and thought-provoking, describing it as one of the best personal finance books with solid advice.","reviews":["Great book. Should be required reading for all high schools. Lessons about money that would have been nice to understand when I first stated working.","Still a good book, but I think it could have been resumed to keep your money invested long term, regardless of the economy to generate compounds...","Easy to read and understand but yet insightful. Especially, the last chapter is a crisp summary of US economic development since World War II"]},{"name":"Readability","sentiment":"positive","text":"Customers find the book very readable and entertaining, describing it as a quick and smooth read.","reviews":["A great read about how to approach thinking about money, but it is so much more than just money. Rather how we approach our lives and what we value....","Easy to read. Written almost like a collection of stories to make his point. Also practical in adding the emotional lens on top of the scientific one.","...Saving and financial planning can be simple. This is a good read for those looking for financial review or general advice on saving for the future."]},{"name":"Value for money","sentiment":"positive","text":"Customers find the book valuable, with several noting it''s worth the time and purchase, and one mentioning it encourages readers to save money.","reviews":["...I’ve recommended it to 5 people in the last week. So worth the read.","...The book is easy to read and grasp. Worth your time if it this topic interests you. Don’t expect a magic pill of knowledge.","...The stories about various individuals are both interesting and valuable. Well worth the time to read."]},{"name":"Storytelling","sentiment":"positive","text":"Customers appreciate the storytelling approach of the book, which uses relatable stories to explain financial concepts.","reviews":["Some great stories and examples but tendency to get hung up in the details. Difficult to recommend for an investment of the time.","...just plain good advice packaged between lots of interesting facts and stories that kept your attention and drove home his points....","...The author explains his view with real life stories and historical facts. I especially enjoy reading the postscript."]},{"name":"Writing style","sentiment":"positive","text":"Customers praise the writing style of the book, noting its conversational approach that makes complex concepts feel straightforward.","reviews":["This book is well written, entertaining, and easy to read. I love how the author teaches financial and life lessons through the use of story telling.","...It’s very well written and at times even made me laugh out loud. Great framework for thinking about not only money, but life goals and values....","A well written book , with a thoughtful approach to investing. Lots of great chapters with plenty of useful information...."]},{"name":"Money","sentiment":"positive","text":"Customers appreciate the book''s approach to money management, finding it helps them understand their relationship with money and provides better ways to use it. One customer notes that managing money involves more than just numbers, while another mentions that saving money is easier than picking stocks for wealth accumulation.","reviews":["It’s the phycology of money! It’s the phycology of money! It’s the phycology of money! It’s the phycology of money! It’s the phycology of money!...","...It gives me a whole new mindset about savings, investing, and what true happiness can look like for me and my family. Well done Morgan Housel!","...I’m glad I did read it. It contains economics, finance, history. I have tons of pages marked for reference...."]},{"name":"Clarity","sentiment":"positive","text":"Customers praise the book''s clarity, noting that it distills complex concepts into accessible language and uses storytelling to make them easy to understand.","reviews":["I really enjoyed reading this book. Very easy to grasp and straight to the point! Never felt dragged out at any point.","A pragmatic and insightful book with a useful framework to guide you in the maze of investing ....","...This will not help you choose a portfolio, but does a great job explaining why we think the way we do about money...."]},{"name":"Simplicity","sentiment":"positive","text":"Customers find the book straightforward and easy to relate to and practice, with one customer noting it''s hard to put down.","reviews":["This is such a great, simple, digestible financial literacy reference. Each chapter tells a short story with a money lesson wrapped up in it....","The book is so easy to understand even for me that im not a financial guy, so glad of the purchase of this book, it open my mind!...","This is an easy and enjoyable read full of wonderful lessons and practical advice...."]}],"features":[]}'::jsonb, '{"title":"The Psychology of Money: Timeless Lessons on Wealth, Greed, and Happiness","author":"Morgan Housel","description":"Alternate cover edition of ISBN 9780857197689. Doing well with money isn’t necessarily about what you know. It’s about how you behave. And behavior is hard to teach, even to really smart people. Money―investing, personal finance, and business decisions―is typically taught as a math-based field, where data and formulas tell us exactly what to do. But in the real world people don’t make financial decisions on a spreadsheet. They make them at the dinner table, or in a meeting room, where personal history, your own unique view of the world, ego, pride, marketing, and odd incentives are scrambled together. In The Psychology of Money, award-winning author Morgan Housel shares 19 short stories exploring the different ways people think about money and teaches you how to make better sense of one of life’s most important topics.","genres":["Finance","Nonfiction","Psychology","Self Help","Business","Money","Personal Finance","Economics","Audiobook","Personal Development"],"averageRating":4.27,"ratingsCount":349768,"ratingsDistribution":{"1":169310,"2":121156,"3":48279,"4":8213,"5":2810},"pages":242,"isbn13":"","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1581527774i/41881472.jpg","publishedAt":"2020-09-08","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/41881472-the-psychology-of-money","reviews":[]}'::jsonb),
  ('Zero to One: Notes on Startups, or How to Build the Future', 'Peter Thiel', 'https://m.media-amazon.com/images/I/51zGCdRQXOL._SL1200_.jpg', 'If you want to build a better future, you must believe in secrets. The great secret of our time is that there are still uncharted frontiers to explore and new inventions to create. In Zero to One, legendary entrepreneur and investor Peter Thiel shows how we can find singular ways to create those new things. Thiel begins with the contrarian premise that we live in an age of technological stagnation, even if we’re too distracted by shiny mobile devices to notice. Information technology has improved rapidly, but there is no reason why progress should be limited to computers or Silicon Valley. Progress can be achieved in any industry or area of business. It comes from the most important skill that every leader must master: learning to think for yourself. Doing what someone else already knows how to do takes the world from 1 to n, adding more of something familiar. But when you do something new, you go from 0 to 1. The next Bill Gates will not build an operating system. The next Larry Page ', 'Business', 195, '9780804139298', '{"title":"Zero to One: Notes on Startups, or How to Build the Future","author":"Peter Thiel","description":"#1 NEW YORK TIMES BESTSELLER • “This book delivers completely new and refreshing ideas on how to create value in the world.”—Mark Zuckerberg, CEO of Meta “Peter Thiel has built multiple breakthrough companies, and Zero to One shows how.”—Elon Musk, CEO of SpaceX and TeslaThe great secret of our time is that there are still uncharted frontiers to explore and new inventions to create. In Zero to One, legendary entrepreneur and investor Peter Thiel shows how we can find singular ways to create those new things.Thiel begins with the contrarian premise that we live in an age of technological stagnation, even if we’re too distracted by shiny mobile devices to notice. Information technology has improved rapidly, but there is no reason why progress should be limited to computers or Silicon Valley. Progress can be achieved in any industry or area of business. It comes from the most important skill that every leader must master: learning to think for yourself.Doing what someone else already knows how to do takes the world from 1 to n, adding more of something familiar. But when you do something new, you go from 0 to 1. The next Bill Gates will not build an operating system. The next Larry Page or Sergey Brin won’t make a search engine. Tomorrow’s champions will not win by competing ruthlessly in today’s marketplace. They will escape competition altogether, because their businesses will be unique.Zero to One presents at once an optimistic view of the future of progress in America and a new way of thinking about innovation: it starts by learning to ask the questions that lead you to find value in unexpected places.","asin":"0804139296","isbn13":"9780804139298","price":"$12.49","listPrice":null,"stars":4.5,"starsBreakdown":{"5star":0.63,"4star":0.27,"3star":0.09,"2star":0.01,"1star":0},"reviewsCount":39864,"thumbnailImage":"https://m.media-amazon.com/images/I/51zGCdRQXOL._SL1200_.jpg","url":"https://www.amazon.com/dp/0804139296","genre":"Economic Policy","publisher":"Crown Currency","pubDate":"September 16, 2014","language":"English","edition":"1st","pageCount":224,"bestsellerRanks":[{"rank":1198,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Economic Policy","url":"https://www.amazon.com/gp/bestsellers/books/5571278011/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Economic Policy & Development (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2588/ref=pd_zg_hrsr_books"},{"rank":2,"category":"Starting a Business (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2751/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  Only 1 left in stock - order soon.","delivery":"Monday, July 6","aiSummary":"Customers find this book to be one of the best business books ever written, enjoying it as a quick read that opens their minds to think differently. Moreover, the book is well-researched and offers invaluable advice, with one customer noting it provides a clear idea of how to think. Additionally, the writing style is intelligently written, with the author speaking from experience, and the book serves as a great primer on startups.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers praise the book''s content, describing it as one of the best business books ever written and a must-read for aspiring entrepreneurs.","reviews":["...For another great book, I recommend Danny Warshay’s book “See, Solve, Scale,” where he described learning why women dropped his class in droves and...","Good book. Short. Good points. Went a little tangential a couple times, but it''s short enough I didn''t mind the scenic route to his points.","Excellent Book!! An approach very different regarding with entrepreneurship. Thanks for share valuable experiences in a simple way."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as a quick, interesting, and concise read that they loved.","reviews":["Great read, lots of profound insight and rare contrarian viewpoints! Could have been more practical but generally brought a lot of good ideas!","...Interesting views with real world experiences. A good read but could have had a little more practical advice and less theory. Still, a very good read.","Easy to read, well summarized tips for tech founders and planning for the future. Would recommend for anyone, even if they''re not in the tech sector."]},{"name":"Insightful","sentiment":"positive","text":"Customers find the book insightful, describing it as a philosophical treatise with thought-provoking ideas and wisdom.","reviews":["...with me, but I found most of the dimensions to be both clear and insightful. I did not expect to like this book as much as I did.","This is one of the best books I read! It’s very insightful while maintaining simplicity. I am holding on to it as I embark on an entrepreneurial path.","Great Insights not only from an entrepreneurial standpoint but also from important areas such as education system, politics , behaviors and personal..."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book very informative, offering invaluable advice and valuable lessons, with one customer noting it is well-researched.","reviews":["Has surpassed my expectations. Original and informative....","Useful and enlightening","...dining table entrepreneur , you will find good analysis, guidance and advice."]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking, describing it as a fascinating collection of ideas that opens their minds to think differently.","reviews":["Liked: - Thoughtful and high-energy. - Clear and concise. - Logic and conclusions drawn are exciting. -...","...One of the best books I’ve ever read . Thiel is practical, smart, direct, and honest","...U get a dash of politics, culture, and philosophy. Definitely a book to read if you are not starting a business as it can be applied to yourself."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, noting it is intelligently and clearly presented by an author who speaks from experience.","reviews":["...Peter''s views on every subject he covers are well thought, well written, and indicative of someone who has thought about very large problems; and...","Very well written, interesting macro-economic perspective, very helpful views on reason-to-be of every startup, VC funding, staffing, start up life...","A well written book. You have to use brain power to understand the subject clearly. Read it two times to grasp the concept. I did."]},{"name":"Concepts","sentiment":"positive","text":"Customers appreciate the book''s concepts, finding it a good source of ideas that promotes innovative inventions and bold thinking.","reviews":["Some interesting ideas; some not so insightful ideas. This book reads like a self-grandizing perspective....","Great book. Peter Thiel is a very interesting intellect with great ideas and thoughts on business and the future.","...stories and lessons from Thiel were refreshing with so many tidbits, ideas and approaches to entrepreneurship enabling you to take your business..."]},{"name":"Starting point","sentiment":"positive","text":"Customers praise this book as one of the best about start-ups, providing solid advice for entrepreneurs and serving as a great primer on the subject.","reviews":["Perhaps the best startup book I have ever read","Peter Thiel is brilliant. The lean startup was nice.. but this book says it all. Everything a mature founder needs to know.","This book starts well but later on he loses focus and rambles about numerous topics that are not worth the time."]}],"features":[]}'::jsonb, '{"title":"Zero to One: Notes on Startups, or How to Build the Future","author":"Peter Thiel","description":"If you want to build a better future, you must believe in secrets. The great secret of our time is that there are still uncharted frontiers to explore and new inventions to create. In Zero to One, legendary entrepreneur and investor Peter Thiel shows how we can find singular ways to create those new things. Thiel begins with the contrarian premise that we live in an age of technological stagnation, even if we’re too distracted by shiny mobile devices to notice. Information technology has improved rapidly, but there is no reason why progress should be limited to computers or Silicon Valley. Progress can be achieved in any industry or area of business. It comes from the most important skill that every leader must master: learning to think for yourself. Doing what someone else already knows how to do takes the world from 1 to n, adding more of something familiar. But when you do something new, you go from 0 to 1. The next Bill Gates will not build an operating system. The next Larry Page or Sergey Brin won’t make a search engine. Tomorrow’s champions will not win by competing ruthlessly in today’s marketplace. They will escape competition altogether, because their businesses will be unique. Zero to One presents at once an optimistic view of the future of progress in America and a new way of thinking about innovation: it starts by learning to ask the questions that lead you to find value in unexpected places.","genres":["Business","Nonfiction","Entrepreneurship","Startup","Self Help","Economics","Technology","Finance","Management","Leadership"],"averageRating":4.14,"ratingsCount":412115,"ratingsDistribution":{"1":196849,"2":123960,"3":59640,"4":16448,"5":15218},"pages":195,"isbn13":"9780804139298","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1630663027i/18050143.jpg","publishedAt":"2014-09-16","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/18050143-zero-to-one","reviews":[]}'::jsonb),
  ('1984', 'George Orwell', 'https://m.media-amazon.com/images/I/71wANojhEKL._SL1500_.jpg', 'A masterpiece of rebellion and imprisonment where war is peace freedom is slavery and Big Brother is watching. Thought Police, Big Brother, Orwellian - these words have entered our vocabulary because of George Orwell''s classic dystopian novel 1984. The story of one man''s Nightmare Odyssey as he pursues a forbidden love affair through a world ruled by warring states and a power structure that controls not only information but also individual thought and memory 1984 is a prophetic haunting tale More relevant than ever before 1984 exposes the worst crimes imaginable the destruction of truth freedom and individuality. With a foreword by Thomas Pynchon. This beautiful paperback edition features deckled edges and french flaps a perfect gift for any occasion Alternate cover edition can be found here.', 'Fiction', 368, '9780452284234', '{"title":"1984: 75th Anniversary","author":"George Orwell","description":"Written 75 years ago, 1984 was George Orwell’s chilling prophecy about the future. And while 1984 has come and gone, his dystopian vision of a government that will do anything to control the narrative is timelier than ever...This 75th Anniversary Edition includes:• A New Introduction by Dolen Perkins-Valdez, author of Take My Hand, winner of the 2023 NAACP Image Award for Outstanding Literary Work—Fiction • A New Afterword by Sandra Newman, author of Julia: A Retelling of George Orwell’s 1984“The Party told you to reject the evidence of your eyes and ears. It was their final, most essential command.”Winston Smith toes the Party line, rewriting history to satisfy the demands of the Ministry of Truth. With each lie he writes, Winston grows to hate the Party that seeks power for its own sake and persecutes those who dare to commit thoughtcrimes. But as he starts to think for himself, Winston can’t escape the fact that Big Brother is always watching...A startling and haunting novel, 1984 creates an imaginary world that is completely convincing from start to finish. No one can deny the novel’s hold on the imaginations of whole generations, or the power of its admonitions—a power that seems to grow, not lessen, with the passage of time.• Nominated as one of America’s best-loved novels by PBS’s The Great American Read •","asin":"0451524934","isbn13":"9780451524935","price":"$6.46","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.75,"4star":0.16,"3star":0.07,"2star":0.01,"1star":0.01},"reviewsCount":125069,"thumbnailImage":"https://m.media-amazon.com/images/I/71wANojhEKL._SL1500_.jpg","url":"https://www.amazon.com/dp/0451524934","genre":"Censorship","publisher":"Signet","pubDate":"July 1, 1950","language":"English","edition":"","pageCount":352,"bestsellerRanks":[{"rank":244,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Political Fiction (Books)","url":"https://www.amazon.com/gp/bestsellers/books/171129/ref=pd_zg_hrsr_books"},{"rank":2,"category":"Censorship & Politics","url":"https://www.amazon.com/gp/bestsellers/books/3825151/ref=pd_zg_hrsr_books"},{"rank":4,"category":"Dystopian Fiction (Books)","url":"https://www.amazon.com/gp/bestsellers/books/3559311011/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock","delivery":"Thursday, July 2","aiSummary":"","aiKeywords":[],"features":[]}'::jsonb, '{"title":"1984","author":"George Orwell","description":"A masterpiece of rebellion and imprisonment where war is peace freedom is slavery and Big Brother is watching. Thought Police, Big Brother, Orwellian - these words have entered our vocabulary because of George Orwell''s classic dystopian novel 1984. The story of one man''s Nightmare Odyssey as he pursues a forbidden love affair through a world ruled by warring states and a power structure that controls not only information but also individual thought and memory 1984 is a prophetic haunting tale More relevant than ever before 1984 exposes the worst crimes imaginable the destruction of truth freedom and individuality. With a foreword by Thomas Pynchon. This beautiful paperback edition features deckled edges and french flaps a perfect gift for any occasion Alternate cover edition can be found here.","genres":["Classics","Fiction","Science Fiction","Dystopia","Literature","Politics","Novels","School","Audiobook","Book Club"],"averageRating":4.2,"ratingsCount":5659221,"ratingsDistribution":{"1":2686118,"2":1868344,"3":788785,"4":206697,"5":109277},"pages":368,"isbn13":"9780452284234","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1657781256i/61439040.jpg","publishedAt":"2022-07-01","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/61439040-1984","reviews":[]}'::jsonb),
  ('The Alchemist', 'Paulo Coelho', 'https://m.media-amazon.com/images/I/71+2-t7M35L._SL1500_.jpg', 'Combining magic, mysticism, wisdom, and wonder into an inspiring tale of self-discovery, The Alchemist has become a modern classic, selling millions of copies around the world and transforming the lives of countless readers across generations. Paulo Coelho''s masterpiece tells the mystical story of Santiago, an Andalusian shepherd boy who yearns to travel in search of a worldly treasure. His quest will lead him to riches far different—and far more satisfying—than he ever imagined. Santiago''s journey teaches us about the essential wisdom of listening to our hearts, recognizing opportunity and learning to read the omens strewn along life''s path, and, most importantly, following our dreams.', 'Fiction', 182, '9780062315007', '{"title":"The Alchemist: A Modern Classic Fable of Spiritual Healing, Self-Discovery, and the Power of Dreams","author":"Paulo Coelho","description":"The extraordinary international bestseller.\n“It’s a brilliant, magical, life-changing book that continues to blow my mind with its lessons.\"—Neil Patrick Harris, actor\n“Translated into 80 languages, the allegory teaches us about dreams, destiny, and the reason we are all here.”—Oprah Daily\nCombining magic, mysticism, wisdom, and wonder into an inspiring tale of self-discovery, this beloved work of philosophical fiction, The Alchemist, has become a modern classic, selling millions of copies around the world and transforming the lives of countless readers across generations.\nThis story, dazzling in its powerful simplicity and soul-stirring wisdom, is about an Andalusian shepherd boy named Santiago who travels from his homeland in Spain to the Egyptian desert in search of a treasure buried near the Pyramids. Along the way he meets a Gypsy woman, a man who calls himself a king, and an alchemist, all of whom point Santiago in the direction of his quest. No one knows what the treasure is, or if Santiago will be able to surmount the obstacles in his path. But what starts out as a journey to find worldly goods turns into a profound journey of spiritual self-discovery.\nLush, evocative, and deeply humane, the story of Santiago is an eternal testament to the transforming power of our dreams and the importance of listening to our hearts.","asin":"0062315005","isbn13":"9780062315007","price":"$9.98","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.75,"4star":0.16,"3star":0.06,"2star":0.02,"1star":0.01},"reviewsCount":182245,"thumbnailImage":"https://m.media-amazon.com/images/I/71+2-t7M35L._SL1500_.jpg","url":"https://www.amazon.com/dp/0062315005","genre":"Historical","publisher":"HarperOne","pubDate":"April 15, 2014","language":"English","edition":"Anniversary","pageCount":208,"bestsellerRanks":[{"rank":141,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Christian Historical Romance","url":"https://www.amazon.com/gp/bestsellers/books/7259439011/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Metaphysical & Visionary Fiction (Books)","url":"https://www.amazon.com/gp/bestsellers/books/271587011/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Christian Historical Fiction (Books)","url":"https://www.amazon.com/gp/bestsellers/books/7259434011/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book to be an inspirational read with great life lessons, accessible language, and meaningful quotes throughout. Moreover, the timeless story delivers a clear message, and customers describe it as lovely and uplifting. Additionally, the book is suitable for readers of all ages, and customers consider it worth the purchase.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers praise the book''s content, describing it as an inspirational read with great life lessons that is both encouraging and enlightening.","reviews":["Such a great book that you should always keep with you!!! I will re-read many times. Extremely powerful message and a book every one should read!","Good book... Great lessons. Would highly recommend and share with friends and family. Would probably read again when I need some inspiration.","Amazing book. So inspirational!! Definitely a must read. You will learn the secrets to live a fulfilling life. You won''t be able to put the book down."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as an incredible and quick read that can be revisited multiple times.","reviews":["This was a great read. I felt like I was on a life changing journey of enlightenment and learning that will impact the way I embrace my own life....","It''s an easy read with life lessons that are written in such a beautiful manner. Would recommend this book to anyone who asks me for a recommendation.","Good read. Ending could use a wee bit if work but worth the literary journey. I would recommend for a long plane ride or fireplace weekend."]},{"name":"Story","sentiment":"positive","text":"Customers appreciate the story of the book, describing it as a nice, simple, and timeless tale with a great moral lesson.","reviews":["One of the best books I have ever read!!😁 Great story, and lessons all throughout the book. I highly recommend this book to anyone!😁😁","A beautifully written book that offers wisdom of life in a beautiful story. Unpredictable and captivating. The title doesn''t do it justice.","Liked the book, fascinating reading. Well written, good story, would recommend it highly. Well structured and easy to read. Thanks."]},{"name":"Writing quality","sentiment":"positive","text":"Customers praise the writing style of the book, describing it as wonderfully and beautifully told, with simple prose that is accessible to readers.","reviews":["Excellent an awesome book about life and the choices we make. Well written and captivating . A great perspective on how we see things in this world.","Although beautifully written never quite got into this book. Didn''t quite have the impact that I expected based on the outstanding reviews.","A fascinating story and very well written. It''s definitely a page turner, even for nonbelievers such as myself. Highly recommended."]},{"name":"Message","sentiment":"positive","text":"Customers appreciate the book''s message, which is clear and filled with meaningful quotes, making it a timeless parable.","reviews":["Classic book with a great message. I especially love this 25th Anniversary Edition. The cover and pages have a unique vintage texture, magical!","Feels kind of like it was written by a child. It had a good message and I wish I could have followed a similar path....","Great book - very thought provoking and inspirational - such a wonderful message. Arrived in good condition as advertised."]},{"name":"Age-appropriate","sentiment":"positive","text":"Customers find the book age-appropriate, noting it is a must-read for people of all ages, particularly good for middle school students, and can be enjoyed by both adults and children.","reviews":["Must read for all ages. I am 22 and a fresh college unsure of her path, why her past has happened the way it did and unsure and afraid of the future....","Great book for all ages !","Great read for teens"]},{"name":"Heartwarming","sentiment":"positive","text":"Customers find the book heartwarming, describing it as lovely and uplifting, with one customer noting how it begins with the longing of the heart.","reviews":["...here and how it is important to reconnect with the world and listen to your heart.It is a must read....","...It is quick read with a storyline of following your dreams and listening to your heart - something that I often need to be reminded of....","What a wonderful story, poignant and relevant; as timeless as Rumi and Kahil Gibran. I absolutely loved and highly recommend!"]},{"name":"Value for money","sentiment":"positive","text":"Customers find the book worth the purchase, describing it as the best investment they''ve ever made.","reviews":["...Encouraging and confirming. Inspiring and so worth the read for anyone feeling the draw to find their treasure and personal legend.","Gorgeous book , great price. Don''t hesitate with his work. This book carries many deeper meanings to the idea of life.","...They seem to be bound unevenly. Even at a good price, I expect a decently constructed product. This book is very sloppily put together."]}],"features":[]}'::jsonb, '{"title":"The Alchemist","author":"Paulo Coelho","description":"Combining magic, mysticism, wisdom, and wonder into an inspiring tale of self-discovery, The Alchemist has become a modern classic, selling millions of copies around the world and transforming the lives of countless readers across generations. Paulo Coelho''s masterpiece tells the mystical story of Santiago, an Andalusian shepherd boy who yearns to travel in search of a worldly treasure. His quest will lead him to riches far different—and far more satisfying—than he ever imagined. Santiago''s journey teaches us about the essential wisdom of listening to our hearts, recognizing opportunity and learning to read the omens strewn along life''s path, and, most importantly, following our dreams.","genres":["Fiction","Classics","Fantasy","Philosophy","Self Help","Book Club","Novels","Spirituality","Audiobook","Adventure"],"averageRating":3.92,"ratingsCount":3689207,"ratingsDistribution":{"1":1465615,"2":1070069,"3":715739,"4":282936,"5":154848},"pages":182,"isbn13":"9780062315007","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1654371463i/18144590.jpg","publishedAt":"2014-04-15","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/18144590-the-alchemist","reviews":[]}'::jsonb),
  ('Deep Work: Rules for Focused Success in a Distracted World', 'Cal Newport', 'https://m.media-amazon.com/images/I/71wSsgrOIhL._SL1500_.jpg', 'One of the most valuable skills in our economy is becoming increasingly rare. If you master this skill, you''ll achieve extraordinary results. Deep work is the ability to focus without distraction on a cognitively demanding task. It''s a skill that allows you to quickly master complicated information and produce better results in less time. Deep work will make you better at what you do and provide the sense of true fulfillment that comes from craftsmanship. In short, deep work is like a super power in our increasingly competitive twenty-first century economy. And yet, most people have lost the ability to go deep-spending their days instead in a frantic blur of e-mail and social media, not even realizing there''s a better way. In Deep Work, author and professor Cal Newport flips the narrative on impact in a connected age. Instead of arguing distraction is bad, he instead celebrates the power of its opposite. Dividing this book into two parts, he first makes the case that in almost any prof', 'Self-help', 296, '9781455586691', '{"title":"Deep Work: Rules for Focused Success in a Distracted World","author":"Cal Newport","description":"Millions of copies sold! The bestselling modern classic that sparked a worldwide conversation about the value of concentration—and the true costs of fractured attention. “I’m handing you the answer to the overwhelm you feel, and his name is Dr. Cal Newport.” —Mel Robbins, The Mel Robbins Podcast, author of New York Times bestselling The Let Them TheoryDeep Work—the ability to focus without distraction on cognitively demanding tasks—is one of the most important abilities you can cultivate in our current moment. It’s a skill that allows you to quickly master complicated information and produce quality results in less time. And yet, most people have lost the ability to go deep—spending their days in a frantic blur of emails, online meetings, social media, and AI slop, not realizing there’s a better way. In Deep Work, bestselling author and professor Cal Newport makes the case for reclaiming focus as a critical skill in our digital world, providing step-by step instructions for achieving this goal, including four rules for transforming your daily habits: 1. Work Deeply 2. Embrace Boredom 3. Quit Social Media 4. Drain the Shallows A mix of cultural criticism and actionable advice, Deep Work offers a vitally important message: in our age of constant distraction, focus is a superpower. With inspiring examples and clear rules, Deep Work will teach you to introduce this ability in your own life.“As a presence on the page, Newport is exceptional in the realm of self-help authors … Six pages in, I powered down my laptop. Twenty pages in, I left the house to buy an alarm clock so that I wouldn’t have an excuse to sleep next to my phone.”—Molly Young, The New York Times “One of the few books I would call life-changing.” —Tim Maurer, Forbes “I’ve read lots of books about productivity and lots of books about distraction. For me, Deep Work is among the best, on both counts.” —Joshua Rothman, The New Yorker “[Deep Work] has changed how I live my life. Particularly, it’s led me to stop scheduling morning meetings, and to preserve that time for more sustained, creative work.” —Ezra Klein, The Ezra Klein Show","asin":"1455586692","isbn13":"9781455586691","price":"$18.34","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.68,"4star":0.24,"3star":0.07,"2star":0.01,"1star":0},"reviewsCount":36342,"thumbnailImage":"https://m.media-amazon.com/images/I/71wSsgrOIhL._SL1500_.jpg","url":"https://www.amazon.com/dp/1455586692","genre":"Workplace Culture","publisher":"Grand Central Publishing","pubDate":"January 5, 2016","language":"English","edition":"1st","pageCount":304,"bestsellerRanks":[{"rank":1032,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":2,"category":"Time Management (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2569/ref=pd_zg_hrsr_books"},{"rank":3,"category":"Workplace Culture (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2571/ref=pd_zg_hrsr_books"},{"rank":4,"category":"Job Hunting & Career Guides","url":"https://www.amazon.com/gp/bestsellers/books/2575/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book to be a must-read that provides ample strategies and suggestions for deep work, with one customer noting it''s particularly valuable for managers and entrepreneurs. Moreover, the book is exhaustively researched and offers practical advice that helps readers proactively progress their primary goals. Additionally, customers appreciate its readability, with one mentioning it provides clear steps, and its thoughtfully written content that helps readers understand the need for focus and make time for meaningful work.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers praise the book''s content, finding it fascinating and a pleasure to read, with one customer noting it''s particularly valuable for managers and entrepreneurs.","reviews":["Great book explaining how you lost your ability to concentrate due to your cell phone and all the apps and distractions that it constantly provides....","Great read with practical tactics to deploy in order to achieve a deep work state consistently. I will be using these tips moving forward!","...Cal, this is an excellent book. It is one that I have already recommended to others. I also bought a 2nd copy to send around my office."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book informative, describing it as exhaustively researched with good insights and the right amount of information.","reviews":["Insightful, very clear, love the examples. Motivational. Inspiring. I learned so much....","Quite a good read. Thought provoking while providing practical ways not simply to manage your time, but to focus on what''s most important in your...","Just great! Deep Work is important for anyone wanting to get the best out of their time and life. Very powerful and demanding. Highly recommend."]},{"name":"Practical advice","sentiment":"positive","text":"Customers appreciate the book''s practical advice, noting that it provides ample strategies and suggestions, with one customer specifically mentioning how it offers actionable ways to perform deep work.","reviews":["One of the most useful books I’ve read. Lots of practical advice on how to achieve more satisfaction from life as well as carve out a position in...","...I really appreciate the good tips on how to start minimizing email stress, and interuptions...","...Helpful for shifting mindset as well as practical ideas, with lots of nuance."]},{"name":"Productivity","sentiment":"positive","text":"Customers find the book helps them become more productive, achieving difficult work and significant results, with one customer noting it helps develop habits for superior outcomes.","reviews":["Finally, a book that explains why I''m happier, more productive and a better writer when I can tune everything out and focus—and, conversely, why I''m...","Great read for anyone who has a job that values higher thinking and productivity. Easy to follow and lots of tips","Has transformed my ability to focus and work deeply. Very rewarding way of working. The quality of work produced is much higher...."]},{"name":"Usefulness","sentiment":"positive","text":"Customers find the book practical and helpful, particularly noting its usefulness for students, and one customer mentions it serves well in their day job.","reviews":["Absolutely worth reading this book to enhance your productivity. Practical and straightforward approach to focused and deep work life habits.","...a ton of valuable information in \"Deep Work\" and I found much of it very helpful, but I did glaze over more than a few times as I made my way...","This is a very useful book...."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as a concise and quick enjoyable read that is challenging and convicting, with one customer noting it provides clear steps for implementation.","reviews":["Insightful reminder to focus on what is important...quick and easy to read. I will read this book again. Would recommend.","I like this easy read. Many good examples, and very easy to actually taken action on....","Great anecdotes, a quick read and a series of actionable steps to get you away from doing the shallow work (e-mail, twitter, etc.)..."]},{"name":"Focus","sentiment":"positive","text":"Customers appreciate the book''s focus on deep concentration and interval training techniques, helping them understand the importance of making time for work that matters.","reviews":["...proactive way possible - by doing, doing, doing with focus, focus, focus.","The core message of this book is simple: deep, focused work is the only place true value is created; and many of our modern ways of living and...","...Cal manages to shed light on the mechanics of concentration and deep focus we all need to produce our best work and the traps of current society..."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, describing it as thoughtfully and wonderfully composed, with easy-to-follow prose and engaging examples throughout.","reviews":["It’s not exactly original, but well written and to the point. Harvested quite a lot useful tips. Like time blocking....","...It''s very well written - Newport has a very clear, concise writing style that helps you get what you need from the material and apply it readily....","Great book. I am truly impressed not only with his writing style, but also with Mr. Newport''s research and excellent and workable..."]}],"features":[]}'::jsonb, '{"title":"Deep Work: Rules for Focused Success in a Distracted World","author":"Cal Newport","description":"One of the most valuable skills in our economy is becoming increasingly rare. If you master this skill, you''ll achieve extraordinary results. Deep work is the ability to focus without distraction on a cognitively demanding task. It''s a skill that allows you to quickly master complicated information and produce better results in less time. Deep work will make you better at what you do and provide the sense of true fulfillment that comes from craftsmanship. In short, deep work is like a super power in our increasingly competitive twenty-first century economy. And yet, most people have lost the ability to go deep-spending their days instead in a frantic blur of e-mail and social media, not even realizing there''s a better way. In Deep Work, author and professor Cal Newport flips the narrative on impact in a connected age. Instead of arguing distraction is bad, he instead celebrates the power of its opposite. Dividing this book into two parts, he first makes the case that in almost any profession, cultivating a deep work ethic will produce massive benefits. He then presents a rigorous training regimen, presented as a series of four \"rules,\" for transforming your mind and habits to support this skill. A mix of cultural criticism and actionable advice, Deep Work takes the reader on a journey through memorable stories-from Carl Jung building a stone tower in the woods to focus his mind, to a social media pioneer buying a round-trip business class ticket to Tokyo to write a book free from distraction in the air-and no-nonsense advice, such as the claim that most serious professionals should quit social media and that you should practice being bored. Deep Work is an indispensable guide to anyone seeking focused success in a distracted world.","genres":["Nonfiction","Self Help","Productivity","Business","Psychology","Personal Development","Audiobook","Personal Growth","Leadership","Management"],"averageRating":4.16,"ratingsCount":195884,"ratingsDistribution":{"1":84010,"2":71329,"3":30373,"4":7676,"5":2496},"pages":296,"isbn13":"9781455586691","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1447957962i/25744928.jpg","publishedAt":"2016-01-05","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/25744928-deep-work","reviews":[]}'::jsonb),
  ('The Lean Startup', 'Eric Ries', 'https://m.media-amazon.com/images/I/71sxTeZIi6L._SL1500_.jpg', 'Most new businesses fail. But most of those failures are preventable.The Lean Startup is a new approach to business that''s being adopted around the world. It is changing the way companies are built and new products are launched. Essential reading for any ambitious entrepreneur, The Lean Startup will teach you to identify what your customers really want. You''ll learn how to test your vision continuously, adapting and adjusting before it''s too late.', 'Business', 299, '9780307887894', '{"title":"The Lean Startup: How Today''s Entrepreneurs Use Continuous Innovation to Create Radically Successful Businesses","author":"Eric Ries","description":"Most startups fail. But many of those failures are preventable. The Lean Startup is a new approach being adopted across the globe, changing the way companies are built and new products are launched. Eric Ries defines a startup as an organization dedicated to creating something new under conditions of extreme uncertainty. This is just as true for one person in a garage or a group of seasoned professionals in a Fortune 500 boardroom. What they have in common is a mission to penetrate that fog of uncertainty to discover a successful path to a sustainable business. The Lean Startup approach fosters companies that are both more capital efficient and that leverage human creativity more effectively. Inspired by lessons from lean manufacturing, it relies on “validated learning,” rapid scientific experimentation, as well as a number of counter-intuitive practices that shorten product development cycles, measure actual progress without resorting to vanity metrics, and learn what customers really want. It enables a company to shift directions with agility, altering plans inch by inch, minute by minute. Rather than wasting time creating elaborate business plans, The Lean Startup offers entrepreneurs—in companies of all sizes—a way to test their vision continuously, to adapt and adjust before it’s too late. Ries provides a scientific approach to creating and managing successful startups in a age when companies need to innovate more than ever.","asin":"0307887898","isbn13":"9780307887894","price":"$13.08","listPrice":null,"stars":4.5,"starsBreakdown":{"5star":0.68,"4star":0.23,"3star":0.07,"2star":0.01,"1star":0.01},"reviewsCount":17876,"thumbnailImage":"https://m.media-amazon.com/images/I/71sxTeZIi6L._SL1500_.jpg","url":"https://www.amazon.com/dp/0307887898","genre":"Small Business","publisher":"Crown Currency","pubDate":"September 13, 2011","language":"English","edition":"First Edition","pageCount":336,"bestsellerRanks":[{"rank":4736,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Starting a Business (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2751/ref=pd_zg_hrsr_books"},{"rank":5,"category":"Small Business (Books)","url":"https://www.amazon.com/gp/bestsellers/books/23696030011/ref=pd_zg_hrsr_books"},{"rank":11,"category":"Entrepreneurship (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2745/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book to be a great read for entrepreneurs, particularly for startups, and appreciate its practical guidance and real-world examples of The Lean Startup methodology in action. The book is well-written and easy to understand, with one customer noting it provides a detailed explanation of agile product management. They value its fresh ideas and comprehensive content, making it a valuable resource for various sectors.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book informative and well-written, particularly noting it as a great guide for startups.","reviews":["Great book, pitty my MBA colleagues didnt read it before our Markstrat class, we could have nailed it as innovators... pitty i was the only one who...","In deed a good book. Love to share it with coworkers to improve the current work methodology. Glad some of my coworkers already learned about it.","Excellent book. It is very nice to see an approach to business based on the scientific method. It was a good read and very well organized."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book very readable and consider it required reading, particularly for those working in tech and starting new businesses.","reviews":["...A great read on world were a lot of products are being commoditized and fast innovation with great customer feedback is required.","...Good read and very good points; I would recommend senior managers and decision makers in corporate world to read this book so they can bring in...","It''s a great book, easy to read and understand. It present many great ideas on how to innovate and change the way we do our work...."]},{"name":"Usefulness","sentiment":"positive","text":"Customers find the book very helpful, particularly for start-ups and product development groups, describing it as a practical and invaluable resource.","reviews":["...It''s practical and it''s easy to remember if we think of it as if we are driving to a destination, we first will envision where it is, then steering...","No complaints. Totally engaging and useful, not just for business, but life in general. Experimenting is, after all, how we learn.","...It was their way of introducing me to the system. I found dozens of helpful, actionable, road-tested strategies in the book to just be more..."]},{"name":"Practical advice","sentiment":"positive","text":"Customers appreciate the practical advice in the book, which provides real-world examples of the Lean Startup methodology in action.","reviews":["...lots of examples and practical advice. I am sure that I will be applying his principles.","...Lots of good advice even for non-start-up companies on how to move/improve the business.","...Great advice and examples, written in an entertaining way...."]},{"name":"Concept","sentiment":"positive","text":"Customers appreciate the book''s concepts, describing them as fresh and deep, with one customer noting that the right experimentation is key to success.","reviews":["This is a book that helps those with great ideas to understand the best way to implement them to keep their passion, creativity, and environments...","Some really good ideas in here! A quick read with lots of good ideas on how to start-up a company with minimal wasted resources and continuous...","great concepts"]},{"name":"Clarity","sentiment":"positive","text":"Customers find the book''s content clear and easy to understand, with one customer noting that it provides lean guidelines to follow.","reviews":["Clear and helpful insights for those about to embark on the start up roller-coaster","...I would recommend it to anyone looking to begin a true start up. Clear definitions and actionable items.","A great set of ideas, but too abstract And theoretical to really be used by most people...."]},{"name":"Examples","sentiment":"positive","text":"Customers appreciate the book''s examples, which are vivid and relevant to the content. One customer notes that the book provides a good mix between theory and practical implementation.","reviews":["...well written, with thought-provoking well chosen use cases and examples, it will profoundly affect the way you think about taking an enterprise to...","Love love love this book. Original ideas (so rare these days) and lots of examples (but not just a collection of stories)....","Vague, has good examples of his own but really not much advice that you could apply to anything even remotely different from the little online-chat..."]},{"name":"Writing quality","sentiment":"positive","text":"Customers praise the book''s writing quality, finding it well and entertainingly written, with one customer noting it is accessible and another mentioning it is based on personal experiences.","reviews":["Well written with thorough case study enhanced learnings. Practical especially as I come from a Lean manufacturing background....","Very well written with lot''s of thought. Many good examples for each recommendation. Great help for us launching a born global company ([...])","...have some background knowledge... Still, this book is really well-written and helpful!"]}],"features":[]}'::jsonb, '{"title":"The Lean Startup","author":"Eric Ries","description":"Most new businesses fail. But most of those failures are preventable.The Lean Startup is a new approach to business that''s being adopted around the world. It is changing the way companies are built and new products are launched. Essential reading for any ambitious entrepreneur, The Lean Startup will teach you to identify what your customers really want. You''ll learn how to test your vision continuously, adapting and adjusting before it''s too late.","genres":["Business","Nonfiction","Entrepreneurship","Startup","Management","Leadership","Buisness","Self Help","Technology","Audiobook"],"averageRating":4.11,"ratingsCount":370520,"ratingsDistribution":{"1":166682,"2":118893,"3":56041,"4":15739,"5":13165},"pages":299,"isbn13":"9780307887894","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1629999184i/10127019.jpg","publishedAt":"2011-01-01","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/10127019-the-lean-startup","reviews":[]}'::jsonb),
  ('Meditations (Penguin Classics)', 'Marcus Aurelius', 'https://m.media-amazon.com/images/I/81DFDGzHZqL._SL1500_.jpg', 'A clear and eloquent leading translation of the Roman emperor’s reflections of human life and death, timeless Stoic philosophy that inspires countless others including The Daily Stoic author Ryan Holiday to use philosophy as a tool for self-improvement and resilience to live a better lifeWritten in Greek by an intellectual Roman emperor without any intention of publication, the Meditations of Marcus Aurelius  offer a wide range of fascinating spiritual reflections and exercises developed as the leader struggled to understand himself and make sense of the universe. Spanning from doubt and despair to conviction and exaltation, they cover such diverse topics as the question of virtue, human rationality, the nature of the gods and the values of leadership. But while the Meditations were composed to provide personal consolation, in developing his beliefs Marcus also created one of the greatest of all works of philosophy: a series of wise and practical aphorisms that have been consulted and ', 'Philosophy', 304, '9780140449334', '{"title":"Meditations (Penguin Classics)","author":"Marcus Aurelius","description":"A clear and eloquent leading translation of the Roman emperor’s reflections of human life and death, timeless Stoic philosophy that inspires countless others including The Daily Stoic author Ryan Holiday to use philosophy as a tool for self-improvement and resilience to live a better lifeWritten in Greek by an intellectual Roman emperor without any intention of publication, the Meditations of Marcus Aurelius  offer a wide range of fascinating spiritual reflections and exercises developed as the leader struggled to understand himself and make sense of the universe. Spanning from doubt and despair to conviction and exaltation, they cover such diverse topics as the question of virtue, human rationality, the nature of the gods and the values of leadership. But while the Meditations were composed to provide personal consolation, in developing his beliefs Marcus also created one of the greatest of all works of philosophy: a series of wise and practical aphorisms that have been consulted and admired by statesmen, thinkers and ordinary readers for almost two thousand years.To provide a full understanding of Aurelius''s seminal work, this edition includes explanatory notes, a general index, an index of quotations, an index of names, and an introduction by Diskin Clay putting the work in its biographical, historical, and literary context, a chronology of Marcus Aurelius''s life and career.Penguin Classics is the leading publisher of classic literature in the English-speaking world, representing a global bookshelf of the best works throughout history and across genres and disciplines. Readers trust the series to provide authoritative texts enhanced by introductions and notes by distinguished scholars and contemporary authors, as well as up-to-date translations by award-winning translators.","asin":"0140449337","isbn13":"9780140449334","price":"$7.26","listPrice":null,"stars":4.8,"starsBreakdown":{"5star":0.87,"4star":0.09,"3star":0.03,"2star":0,"1star":0.01},"reviewsCount":9618,"thumbnailImage":"https://m.media-amazon.com/images/I/81DFDGzHZqL._SL1500_.jpg","url":"https://www.amazon.com/dp/0140449337","genre":"Ancient Greek & Roman","publisher":"Penguin Classics","pubDate":"October 31, 2006","language":"English","edition":"","pageCount":304,"bestsellerRanks":[{"rank":1473,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":2,"category":"Ancient Roman History (Books)","url":"https://www.amazon.com/gp/bestsellers/books/4883/ref=pd_zg_hrsr_books"},{"rank":5,"category":"Ancient Greek & Roman Philosophy","url":"https://www.amazon.com/gp/bestsellers/books/11047/ref=pd_zg_hrsr_books"},{"rank":7,"category":"Philosophy Movements (Books)","url":"https://www.amazon.com/gp/bestsellers/books/886134/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book to be an excellent work of philosophy that is easy to read and comprehend, with well-translated content and Marcus Aurelius''s brilliant writing style. Moreover, the book includes comprehensive author notes, making it a timeless classic that customers say will change their lives. Additionally, they appreciate the daily meditations, with one customer noting how it provides peace about the nature of things.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find this book to be an excellent work of philosophy and a must-read for anyone interested in the subject, with one customer noting it as a famous read by a general.","reviews":["...or wanting to learn more about the Stoic philosophy this is a great book.","Good book","Amazing book, however better quality of shipment is expected when buying from an Amazon warehouse. Came in 3 days with prime...."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book easy to read and comprehend, taking only a short time to complete, with one customer noting that the concepts are simple enough for casual readers to grasp.","reviews":["Easy read. Thought linger on. Pick up put down. Read at bed time","...For those unfamiliar, it reads easily and has a non-academic feel without sinking to a \"dear diary\" sappiness....","...it’s philosophical, a lot of the advice is simple and easy to apply to everyday life...."]},{"name":"Translation","sentiment":"positive","text":"Customers appreciate the translation of the book, with one noting that it avoids pretentious language.","reviews":["Great book written and well translated. There are a few translations that are translated to a bit more contemporary language....","This book is a must read, and the translation is good.","...It is also very well translated."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, finding it brilliant and compelling, with several noting that it is actually written by Marcus Aurelius. One customer mentions that it is written in aphorisms.","reviews":["Great book written and well translated. There are a few translations that are translated to a bit more contemporary language....","...He is such a compelling writer that I think it is all too easy to read MA in a way that avoids how radical are some of his ideas....","I read and re-read a piece of this book every day. Phenomenal writing and as relevant as ever."]},{"name":"Instructions","sentiment":"positive","text":"Customers appreciate the detailed notes throughout the book, with one customer noting that the author provides explanations for everything, and another mentioning the excellent introduction and footnotes.","reviews":["The book has an introduction, 12 chapters (\"12 books\"), then a notes section in the back where the author gives his notes on everything....","...It is still an excellent instruction manual for how to live a good life, even today","...I like this Penguin Classics edition. The introduction by Diskin Clay is useful, the translation by Martin Hammond is mostly accurate and his..."]},{"name":"Classic","sentiment":"positive","text":"Customers appreciate this book as a classic, with one customer describing it as a historical masterpiece.","reviews":["Classic book and it’s a penguin edition. Must read for anyone interested in this subject. I highly recommend it cause it’s a penguin edition.","Classic.","What makes Meditations an important book is that it provides the opportunity to discuss what it is to be human, to have a soul, to live a good life..."]},{"name":"Life lessons","sentiment":"positive","text":"Customers appreciate the life lessons in the book, with several noting it will change their lives, and one customer highlighting its timeless advice on dealing with life''s struggles, while another mentions how it kept them strong in times of stress and danger.","reviews":["Fantastic book. Deeply healing and like a set of tools for the ailments of the mind....","Buy this- it is fantastic, and will change your life.","...and find it within myself to lead an emotionally and psychologically balanced life. My life is forever changed for the better...."]},{"name":"Meditation","sentiment":"positive","text":"Customers appreciate the meditations in the book, finding them great for daily practice, with one customer noting how they help calm the mind and another mentioning how they focus on what we can control.","reviews":["It is a great read and makes you stop and think","Great daily meditations. Bought this book a while ago and still refer to it from time to time.","...Simple and yet profound . I find that when I read it my mind calms and i am completely relaxed...."]}],"features":[]}'::jsonb, NULL),
  ('Educated', 'Tara Westover', 'https://m.media-amazon.com/images/I/71-4MkLN5jL._SL1500_.jpg', '#1 NEW YORK TIMES, WALL STREET JOURNAL, AND BOSTON GLOBE BESTSELLER • One of the most acclaimed books of our time: an unforgettable memoir about a young woman who, kept out of school, leaves her survivalist family and goes on to earn a PhD from Cambridge University “Extraordinary . . . an act of courage and self-invention.”—The New York Times NAMED ONE OF THE TEN BEST BOOKS OF THE YEAR BY THE NEW YORK TIMES BOOK REVIEW • ONE OF BARACK OBAMA’S FAVORITE BOOKS OF THE YEAR • A KIRKUS REVIEWS BEST NONFICTION BOOK OF THE CENTURY • FINALIST: National Book Critics Circle’s Award In Autobiography and John Leonard Prize For Best First Book • PEN/Jean Stein Book Award • Los Angeles Times Book Prize Born to survivalists in the mountains of Idaho, Tara Westover was seventeen the first time she set foot in a classroom. Her family was so isolated from mainstream society that there was no one to ensure the children received an education, and no one to intervene when one of Tara’s older brothers became', 'Non-fiction', 352, '9780399590504', '{"title":"Educated: A Memoir","author":"Tara Westover","description":"#1 NEW YORK TIMES, WALL STREET JOURNAL, AND BOSTON GLOBE BESTSELLER • One of the most acclaimed books of our time: an unforgettable memoir about a young woman who, kept out of school, leaves her survivalist family and goes on to earn a PhD from Cambridge University“Extraordinary . . . an act of courage and self-invention.”—The New York TimesNAMED ONE OF THE TEN BEST BOOKS OF THE YEAR BY THE NEW YORK TIMES BOOK REVIEW • ONE OF BARACK OBAMA’S FAVORITE BOOKS OF THE YEAR • A KIRKUS REVIEWS BEST NONFICTION BOOK OF THE CENTURY • FINALIST: National Book Critics Circle’s Award In Autobiography and John Leonard Prize For Best First Book • PEN/Jean Stein Book Award • Los Angeles Times Book PrizeBorn to survivalists in the mountains of Idaho, Tara Westover was seventeen the first time she set foot in a classroom. Her family was so isolated from mainstream society that there was no one to ensure the children received an education, and no one to intervene when one of Tara’s older brothers became violent. When another brother got himself into college, Tara decided to try a new kind of life. Her quest for knowledge transformed her, taking her over oceans and across continents, to Harvard and to Cambridge University. Only then would she wonder if she’d traveled too far, if there was still a way home.“Beautiful and propulsive . . . Despite the singularity of [Westover’s] childhood, the questions her book poses are universal: How much of ourselves should we give to those we love? And how much must we betray them to grow up?”—VogueONE OF THE BEST BOOKS OF THE YEAR: The Washington Post, O: The Oprah Magazine, Time, NPR, Good Morning America, San Francisco Chronicle, The Guardian, The Economist, Financial Times, Newsday, New York Post, theSkimm, Refinery29, Bloomberg, Self, Real Simple, Town & Country, Bustle, Paste, Publishers Weekly, Library Journal, LibraryReads, Book Riot, Pamela Paul, KQED, New York Public Library","asin":"0399590501","isbn13":"9780399590504","price":"$14.47","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.74,"4star":0.19,"3star":0.05,"2star":0.01,"1star":0.01},"reviewsCount":229769,"thumbnailImage":"https://m.media-amazon.com/images/I/71-4MkLN5jL._SL1500_.jpg","url":"https://www.amazon.com/dp/0399590501","genre":"Religious","publisher":"Random House","pubDate":"February 20, 2018","language":"English","edition":"First Edition","pageCount":352,"bestsellerRanks":[{"rank":3110,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":2,"category":"Religious Leader Biographies","url":"https://www.amazon.com/gp/bestsellers/books/2398/ref=pd_zg_hrsr_books"},{"rank":3,"category":"Women''s Biographies","url":"https://www.amazon.com/gp/bestsellers/books/2445/ref=pd_zg_hrsr_books"},{"rank":3,"category":"Regional U.S. Biographies","url":"https://www.amazon.com/gp/bestsellers/books/2430/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  Only 2 left in stock - order soon.","delivery":"Thursday, July 2","aiSummary":"","aiKeywords":[],"features":[]}'::jsonb, '{"title":"Educated","author":"Tara Westover","description":"#1 NEW YORK TIMES, WALL STREET JOURNAL, AND BOSTON GLOBE BESTSELLER • One of the most acclaimed books of our time: an unforgettable memoir about a young woman who, kept out of school, leaves her survivalist family and goes on to earn a PhD from Cambridge University “Extraordinary . . . an act of courage and self-invention.”—The New York Times NAMED ONE OF THE TEN BEST BOOKS OF THE YEAR BY THE NEW YORK TIMES BOOK REVIEW • ONE OF BARACK OBAMA’S FAVORITE BOOKS OF THE YEAR • A KIRKUS REVIEWS BEST NONFICTION BOOK OF THE CENTURY • FINALIST: National Book Critics Circle’s Award In Autobiography and John Leonard Prize For Best First Book • PEN/Jean Stein Book Award • Los Angeles Times Book Prize Born to survivalists in the mountains of Idaho, Tara Westover was seventeen the first time she set foot in a classroom. Her family was so isolated from mainstream society that there was no one to ensure the children received an education, and no one to intervene when one of Tara’s older brothers became violent. When another brother got himself into college, Tara decided to try a new kind of life. Her quest for knowledge transformed her, taking her over oceans and across continents, to Harvard and to Cambridge University. Only then would she wonder if she’d traveled too far, if there was still a way home. “Beautiful and propulsive . . . Despite the singularity of [Westover’s] childhood, the questions her book poses are universal: How much of ourselves should we give to those we love? And how much must we betray them to grow up?”—Vogue ONE OF THE BEST BOOKS OF THE YEAR: The Washington Post, O: The Oprah Magazine, Time, NPR, Good Morning America, San Francisco Chronicle, The Guardian, The Economist, Financial Times, Newsday, New York Post, theSkimm, Refinery29, Bloomberg, Self, Real Simple, Town &amp; Country, Bustle, Paste, Publishers Weekly, Library Journal, LibraryReads, Book Riot, Pamela Paul, KQED, New York Public Library","genres":["Nonfiction","Memoir","Book Club","Biography","Audiobook","Biography Memoir","Autobiography","Education","Adult","Religion"],"averageRating":4.46,"ratingsCount":1934588,"ratingsDistribution":{"1":1165993,"2":564042,"3":156034,"4":32079,"5":16440},"pages":352,"isbn13":"9780399590504","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1774287363i/35133922.jpg","publishedAt":"2018-02-20","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/35133922-educated","reviews":[]}'::jsonb),
  ('The Hard Thing About Hard Things: Building a Business When There Are No Easy Answers―Straight Talk on the Challenges of Entrepreneurship', 'Ben Horowitz', 'https://m.media-amazon.com/images/I/810u9MkT3SL._SL1500_.jpg', 'A lot of people talk about how great it is to start a business, but only Ben Horowitz is brutally honest about how hard it is to run one. In The Hard Thing About Hard Things, Ben Horowitz, cofounder of Andreessen Horowitz and one of Silicon Valley''s most respected and experienced entrepreneurs, draws on his own story of founding, running, selling, buying, managing, and investing in technology companies to offer essential advice and practical wisdom for navigating the toughest problems business schools don''t cover. His blog has garnered a devoted following of millions of readers who have come to rely on him to help them run their businesses. A lifelong rap fan, Horowitz amplifies business lessons with lyrics from his favorite songs and tells it straight about everything from firing friends to poaching competitors, from cultivating and sustaining a CEO mentality to knowing the right time to cash in. His advice is grounded in anecdotes from his own hard-earned rise—from cofounding the ear', 'Business', 304, '9780062273208', '{"title":"The Hard Thing About Hard Things: Building a Business When There Are No Easy Answers―Straight Talk on the Challenges of Entrepreneurship","author":"Ben Horowitz","description":"Ben Horowitz, cofounder of the venture capital firm Andreessen Horowitz and one of Silicon Valley’s most respected and experienced entrepreneurs, offers essential leadership advice on building and running a startup―practical wisdom for managing the toughest problems business school doesn’t cover, based on his popular ben’s blog.\nWhile many people talk about how great it is to start a business, very few are honest about how difficult entrepreneurship is when it comes to running one. Ben Horowitz analyzes the problems that confront leaders every day, sharing the insights he’s gained developing, managing, selling, buying, investing in, and supervising technology companies. A lifelong rap fanatic, he amplifies business lessons with lyrics from his favorite songs, telling it straight about everything from firing friends to poaching competitors, cultivating and sustaining a CEO mentality to knowing the right time to cash in.\nFilled with his trademark humor and straight talk, The Hard Thing About Hard Things is an invaluable management book for veteran entrepreneurs as well as those aspiring to their own new ventures, drawing from Horowitz''s personal and often humbling experiences.\nThis is not another theoretical management guide. It’s a field manual for the toughest challenges you’ll face as a leader:\nThe CEO Mentality: Learn how to make the right call when there are no good options, from firing loyal friends to knowing the right time to cash in.\nThe CEO Mentality: Learn how to make the right call when there are no good options, from firing loyal friends to knowing the right time to cash in.\nStartup Advice: Get unflinching, practical wisdom for the real problems business school doesn’t cover, drawn from Horowitz’s own humbling experiences.\nStartup Advice: Get unflinching, practical wisdom for the real problems business school doesn’t cover, drawn from Horowitz’s own humbling experiences.\nWartime Leadership: Understand the hard-won insights gained from developing, managing, and selling technology companies through the dot-com crash and beyond.\nWartime Leadership: Understand the hard-won insights gained from developing, managing, and selling technology companies through the dot-com crash and beyond.\nUnconventional Wisdom: See how lessons from his favorite rap songs can be amplified to solve the most complex business challenges.\nUnconventional Wisdom: See how lessons from his favorite rap songs can be amplified to solve the most complex business challenges.","asin":"0062273205","isbn13":"9780062273208","price":"$15.22","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.71,"4star":0.21,"3star":0.07,"2star":0.01,"1star":0},"reviewsCount":15779,"thumbnailImage":"https://m.media-amazon.com/images/I/810u9MkT3SL._SL1500_.jpg","url":"https://www.amazon.com/dp/0062273205","genre":"Company Profiles","publisher":"Harper Business","pubDate":"March 4, 2014","language":"English","edition":"","pageCount":304,"bestsellerRanks":[{"rank":4831,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":3,"category":"Starting a Business (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2751/ref=pd_zg_hrsr_books"},{"rank":6,"category":"Strategy & Competition","url":"https://www.amazon.com/gp/bestsellers/books/2553/ref=pd_zg_hrsr_books"},{"rank":10,"category":"Business Mentoring & Coaching (Books)","url":"https://www.amazon.com/gp/bestsellers/books/10020710011/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book excellent for learning about business, with solid advice and practical tools for CEOs and senior executives. Moreover, the book features real-life stories and is worth rereading multiple times, with one customer noting it reads like a suspense novel. Additionally, customers appreciate its honest approach, concise content, and engaging style, making it a must-read for anyone getting started in business.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers praise the book''s content, describing it as a brilliant and excellent management guide that provides solid advice.","reviews":["Great book, and actually pretty interesting reading for a business book. Some succinct, actionable, clear guidance for how to handle tough situations.","Excellent book, easy reading and the essentials to know about the hard things.","Insightful, wise, refreshingly honest. A brilliant book for any businessperson wanting to be so. Thanks for being transparent and willing to share."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book easy to read and thoroughly engaging, with many noting it''s worth rereading several times and considering it a must-read for anyone getting started in entrepreneurship.","reviews":["An easy, straight-forward account which was also a great read. A pretty unique insight of which you can''t help but be a little fascinated....","Interesting and easy read. Ben reiterated a lot of lessons he learned from running Opsware, which became a little tedious to read about....","Very good book must read. Very good book must read. Very good book must read. Very good book must read very good book must read...."]},{"name":"Practicality","sentiment":"positive","text":"Customers find the book practical and actionable, with one customer noting it provides valuable suggestions and another highlighting its useful tools for CEOs and senior executives.","reviews":["...After a year or 2 go back and read this book. It is practical and dives into detail when needed. And he tells the story.","A little rough around the edges. But honest. And useful. Covers a lot of problems that are common with start-ups....","...Very practical and honest and most of the content will resonate with most entrepreneurs that have found themselves starting and running a company as..."]},{"name":"Story","sentiment":"positive","text":"Customers appreciate the book''s stories, describing them as wonderful war stories and real life experiences, with one customer noting how they apply to all businesses.","reviews":["...in and already am enjoying the book -- there''s a lot of interesting stories and great anecdotal advice....","...Hard Thing About Hard Things is a combination of Ben Horowitz''s interesting story and a cautionary, scared-straight tale of the challenges faced by...","I love this book. Great story telling and real, practical advise that you can''t find elsewhere."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book informative, describing it as a comprehensive reference guide that offers practical information and follows general concepts.","reviews":["...The book is a practical, actionable, personal guide to the constant struggle of building a business.","...This unassigned reading is some of the best info I''ve come across.","Thorough, honest, direct advice on how to deal with \"the struggle\" of running a high growth company. Highly recommend it."]},{"name":"Honesty","sentiment":"positive","text":"Customers appreciate the book''s honesty, describing it as refreshing and true, with one customer noting it as a no BS memoir.","reviews":["This book is sufficiently detailed and honest as to make me think I might actually be able to pull off starting the company of my dreams. I loved it.","Frank, fast-paced, and not without insight....","Ben does not need my endorsement but I owe it to him for his efforts & honesty and to the future readers for their conviction to read the book...."]},{"name":"Engaging","sentiment":"positive","text":"Customers find the book engaging and entertaining, with one customer noting its great balance between information and entertainment.","reviews":["For a book that deals with business management, this is an entertaining and compelling read....","Interesting and easy read. Ben reiterated a lot of lessons he learned from running Opsware, which became a little tedious to read about....","a brilliant, thoughtful, fun read about what it is really like to try to run a modern company, what the actual challenges are and how to try to see..."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, finding it well and concisely written, with one customer noting its pragmatic approach in compact sequences.","reviews":["Good and deep book about entrepeneurship and struggles of being CEO. Well written and really enjoyable. Well constructed yet poetical reading.","...Very well written and deeply honest, it can be read either front-to-back or be used as a manual of indepe, discarding anything that the reader do...","This well written book is great for those seeking leadership and management advice...."]}],"features":[]}'::jsonb, '{"title":"The Hard Thing About Hard Things: Building a Business When There Are No Easy Answers―Straight Talk on the Challenges of Entrepreneurship","author":"Ben Horowitz","description":"A lot of people talk about how great it is to start a business, but only Ben Horowitz is brutally honest about how hard it is to run one. In The Hard Thing About Hard Things, Ben Horowitz, cofounder of Andreessen Horowitz and one of Silicon Valley''s most respected and experienced entrepreneurs, draws on his own story of founding, running, selling, buying, managing, and investing in technology companies to offer essential advice and practical wisdom for navigating the toughest problems business schools don''t cover. His blog has garnered a devoted following of millions of readers who have come to rely on him to help them run their businesses. A lifelong rap fan, Horowitz amplifies business lessons with lyrics from his favorite songs and tells it straight about everything from firing friends to poaching competitors, from cultivating and sustaining a CEO mentality to knowing the right time to cash in. His advice is grounded in anecdotes from his own hard-earned rise—from cofounding the early cloud service provider Loudcloud to building the phenomenally successful Andreessen Horowitz venture capital firm, both with fellow tech superstar Marc Andreessen (inventor of Mosaic, the Internet''s first popular Web browser). This is no polished victory lap; he analyzes issues with no easy answers through his trials, including demoting (or firing) a loyal friend; whether you should incorporate titles and promotions, and how to handle them; if it''s OK to hire people from your friend''s company; how to manage your own psychology, while the whole company is relying on you; what to do when smart people are bad employees; why Andreessen Horowitz prefers founder CEOs, and how to become one; whether you should sell your company, and how to do it. Filled with Horowitz''s trademark humor and straight talk, and drawing from his personal and often humbling experiences, The Hard Thing About Hard Things is invaluable for veteran entrepreneurs as well as those aspiring to their own new ventures.","genres":["Business","Nonfiction","Entrepreneurship","Leadership","Management","Startup","Self Help","Buisness","Audiobook","Biography"],"averageRating":4.19,"ratingsCount":112958,"ratingsDistribution":{"1":54608,"2":35337,"3":16046,"4":4242,"5":2725},"pages":304,"isbn13":"9780062273208","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1386609333i/18176747.jpg","publishedAt":"2014-03-04","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/18176747-the-hard-thing-about-hard-things","reviews":[]}'::jsonb),
  ('Man''s Search for Meaning', 'Viktor E. Frankl', 'https://m.media-amazon.com/images/I/81UhnGT7BvL._SL1500_.jpg', 'Psychiatrist Viktor Frankl''s memoir has riveted generations of readers with its descriptions of life in Nazi death camps and its lessons for spiritual survival. Based on his own experience and the stories of his patients, Frankl argues that we cannot avoid suffering but we can choose how to cope with it, find meaning in it, and move forward with renewed purpose. At the heart of his theory, known as logotherapy, is a conviction that the primary human drive is not pleasure but the pursuit of what we find meaningful. Man''s Search for Meaning has become one of the most influential books in America; it continues to inspire us all to find significance in the very act of living.', 'Philosophy', 165, '9780807014295', '{"title":"Man''s Search for Meaning","author":"Viktor E. Frankl","description":"A book for finding purpose and strength in times of great despair, the international best-seller is still just as relevant today as when it was first published.“He who has a why to live can bear almost any how” is the central theme in Man''s Search For Meaning.This seminal book, which has been called “one of the outstanding contributions to psychological thought” by Carl Rogers and “one of the great books of our time” by Harold Kushner, has been translated into more than fifty languages and sold over sixteen million copies. “An enduring work of survival literature,” according to the New York Times, Viktor Frankl’s riveting account of his time in the Nazi concentration camps, and his insightful exploration of the human will to find meaning in spite of the worst adversity, has offered solace and guidance to generations of readers since it was first published in 1946. At the heart of Frankl’s theory of logotherapy (from the Greek word for “meaning”) is a conviction that the primary human drive is not pleasure, as Freud maintained, but rather the discovery and pursuit of what the individual finds meaningful. Today, as new generations face new challenges and an ever more complex and uncertain world, Frankl’s classic work continues to inspire us all to find significance in the very act of living, in spite of all obstacles.A must-read companion to this classic work, a new, never-before-published work by Frankl entitled Yes to Life: In Spite of Everything, is now available in English.","asin":"0807014273","isbn13":"9780807014271","price":"$12.01","listPrice":null,"stars":4.7,"starsBreakdown":{"5star":0.78,"4star":0.16,"3star":0.05,"2star":0.01,"1star":0},"reviewsCount":99156,"thumbnailImage":"https://m.media-amazon.com/images/I/81UhnGT7BvL._SL1500_.jpg","url":"https://www.amazon.com/dp/0807014273","genre":"Existential","publisher":"Beacon Press","pubDate":"June 1, 2006","language":"English","edition":"1st","pageCount":184,"bestsellerRanks":[{"rank":159,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Popular Psychology Psychotherapy","url":"https://www.amazon.com/gp/bestsellers/books/11203/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Popular Psychology Psychoanalysis","url":"https://www.amazon.com/gp/bestsellers/books/11199/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Existential Psychology (Books)","url":"https://www.amazon.com/gp/bestsellers/books/10166943011/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book life-changing and deeply inspiring, with one describing it as a beautiful account of personal courage. The book is easy to understand and thought-provoking, with one customer noting how it challenges readers to find their own meaning and path. They appreciate its emotional content, with one review highlighting its message about suffering, and find it helpful in guiding them through life situations.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find this book to be a life-changing read, with one customer describing it as an incredible account.","reviews":["Great book and very insightful into how people deal with impossible circumstances and come out the other side.. His psychology seems sound and less...","An amazing book!!! This should be required reading in school even with the descriptions of death camps. This book has given me a new outlook on life....","Excellent book that was not what I expected. This book answered a lot of questions for me and forced me introspect about my life and what I can do."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book readable, describing it as a fascinating and deep read, with one customer noting it is easy to understand.","reviews":["...language a bit unnecessarily confusing or ill worded - nonetheless great read and eye opening for those willing to really digest what Viktor Frankl...","these days these times, this is a good read, and one to give thought too about life, the why''s, the how''s of where we are today as a society.....and...","A must read. In my top 5 books relating to life and mastering the self. Easy book with tons of phrases you will be storing as reference."]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking and insightful, with one customer noting how it makes you think about life.","reviews":["...This is a wonderful, quick, insightful,inspiring book. Written in direct and simple terms this book is recommended to all!","Very moving book! Thought provoking! A book that crosses the generations! The kind of book that can be reread because each time sheds new light!","I enjoyed this book very much. Very insightful and inspiring. I believe everyone should be expected to read this to give perspective to their lives."]},{"name":"Inspirational","sentiment":"positive","text":"Customers find the book deeply inspiring, describing it as a profound and powerful message that serves as a wonderful motivator.","reviews":["Motivating, inspiring, and empowering, especially for those suffering from experiencing the existential vacuum. I will recommend this book to anyone!","Profound. Reflective. Transcendent. This book is extremely transformative. I will rethink the logos of my life and find the why to endure any how.","...It is inspirational and comforting to know that a person can find meaning in life through suffering, tragedy, and hard times from one’s attitude..."]},{"name":"Meaning","sentiment":"positive","text":"Customers find the book meaningful, with several noting it challenges them to find their own purpose and path in life. One customer describes it as the blueprint for a meaningful existence.","reviews":["...it as a Birthday gift for a person who I believe will also find it meaningful and enlightening. (I''ll ask to borrow it when he''s done.)","...The content is difficult to read, but very meaningful, as the title suggests. It''s certainly not for the faint of heart....","This book clarified me exactly what the words, meaning of life,is all about. It gave me a sense of spiritual tranquility and happiness...."]},{"name":"Emotional","sentiment":"positive","text":"Customers find the book emotionally powerful, describing it as a soul-grabbing and heart-breaking account that is both touching and humbling.","reviews":["Uplifting and transformative, I''ll be passing this book along to my teenaged son. I wish all of those who are suffering could read it.","The first part of the book was well-written, poignant and interesting. However the second part was pendantic and thus boring....","...author''s experiences in the Nazi death camps was very interesting and touching. It is a very moving testament to what the human spirit can endure...."]},{"name":"Story","sentiment":"positive","text":"Customers appreciate the story of the book, describing it as an amazing and captivating account of survival that provides insight into tragic events.","reviews":["What Frankl endured and how he persevered is just an amazing story! Frankl gets you to find the meaning in your life and can change your outlook!","Great story to remind each other to stay positive in any circumstances and keep going in life. Highly recommended to reading it over and over again","...This a book that you keep and read every few years. It''s an incredible story and it''s deeply moving...."]},{"name":"Practical","sentiment":"positive","text":"Customers find the book very helpful in their lives, guiding them through various situations, and consider it one of the most beneficial books they''ve read.","reviews":["...as opposed to Freud''s Psychoanalysis, is simple, logical, human, and helpful. I wish I had known about Frankl''s teaching earlier.","Inspiring and applicable to daily life, practical and almost magical at times--the way Frankl was able to put perspective to situations or use his...","...Important, challenging and essential material for learning to live in today''s world of uncertainty."]}],"features":[]}'::jsonb, '{"title":"Man''s Search for Meaning","author":"Viktor E. Frankl","description":"Psychiatrist Viktor Frankl''s memoir has riveted generations of readers with its descriptions of life in Nazi death camps and its lessons for spiritual survival. Based on his own experience and the stories of his patients, Frankl argues that we cannot avoid suffering but we can choose how to cope with it, find meaning in it, and move forward with renewed purpose. At the heart of his theory, known as logotherapy, is a conviction that the primary human drive is not pleasure but the pursuit of what we find meaningful. Man''s Search for Meaning has become one of the most influential books in America; it continues to inspire us all to find significance in the very act of living.","genres":["Nonfiction","Psychology","Philosophy","History","Self Help","Memoir","Biography","Classics","Audiobook","Spirituality"],"averageRating":4.37,"ratingsCount":917955,"ratingsDistribution":{"1":510128,"2":275957,"3":101207,"4":20721,"5":9942},"pages":165,"isbn13":"9780807014295","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1535419394i/4069.jpg","publishedAt":"2006-06-01","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/4069.Man_s_Search_for_Meaning","reviews":[]}'::jsonb),
  ('Ikigai: The Japanese Secret to a Long and Happy Life', 'Héctor García', 'https://m.media-amazon.com/images/I/71lJBs5MNlL._SL1500_.jpg', 'INTERNATIONAL BESTSELLER • 5 MILLION+ COPIES SOLD WORLDWIDE“Workers looking for more fulfilling positions should start by identifying their ikigai.” ―Business Insider“One of the unintended—yet positive—consequences of the [pandemic] is that it is forcing people to reevaluate their jobs, careers, and lives. Use this time wisely, find your personal ikigai, and live your best life.” ―ForbesFind your ikigai (pronounced ee-key-guy) to live longer and bring more meaning and joy to all your days.“Only staying active will make you want to live a hundred years.” —Japanese proverb According to the Japanese, everyone has an ikigai—a reason for living. And according to the residents of the Japanese village with the world’s longest-living people, finding it is the key to a happier and longer life. Having a strong sense of ikigai—where what you love, what you’re good at, what you can get paid for, and what the world needs all overlap—means that each day is infused with meaning. It’s the reason we ge', 'Self-help', 208, '9780143130727', '{"title":"Ikigai: The Japanese Secret to a Long and Happy Life","author":"Héctor García","description":"INTERNATIONAL BESTSELLER • 5 MILLION+ COPIES SOLD WORLDWIDE“Workers looking for more fulfilling positions should start by identifying their ikigai.” ―Business Insider“One of the unintended—yet positive—consequences of the [pandemic] is that it is forcing people to reevaluate their jobs, careers, and lives. Use this time wisely, find your personal ikigai, and live your best life.” ―ForbesFind your ikigai (pronounced ee-key-guy) to live longer and bring more meaning and joy to all your days.“Only staying active will make you want to live a hundred years.” —Japanese proverb According to the Japanese, everyone has an ikigai—a reason for living. And according to the residents of the Japanese village with the world’s longest-living people, finding it is the key to a happier and longer life. Having a strong sense of ikigai—where what you love, what you’re good at, what you can get paid for, and what the world needs all overlap—means that each day is infused with meaning. It’s the reason we get up in the morning. It’s also the reason many Japanese never really retire (in fact there’s no word in Japanese that means retire in the sense it does in English): They remain active and work at what they enjoy, because they’ve found a real purpose in life—the happiness of always being busy.In researching this book, the authors interviewed the residents of the Japanese village with the highest percentage of 100-year-olds—one of the world’s Blue Zones. Ikigai reveals the secrets to their longevity and happiness: how they eat, how they move, how they work, how they foster collaboration and community, and—their best-kept secret—how they find the ikigai that brings satisfaction to their lives. And it provides practical tools to help you discover your own ikigai. Because who doesn’t want to find happiness in every day?What’s your ikigai?","asin":"0143130722","isbn13":"9780143130727","price":"$10.06","listPrice":null,"stars":4.5,"starsBreakdown":{"5star":0.69,"4star":0.19,"3star":0.09,"2star":0.02,"1star":0.01},"reviewsCount":67657,"thumbnailImage":"https://m.media-amazon.com/images/I/71lJBs5MNlL._SL1500_.jpg","url":"https://www.amazon.com/dp/0143130722","genre":"Aging & Longevity","publisher":"Penguin Life","pubDate":"August 29, 2017","language":"English","edition":"Illustrated","pageCount":208,"bestsellerRanks":[{"rank":283,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Aging & Longevity (Books)","url":"https://www.amazon.com/gp/bestsellers/books/11764645011/ref=pd_zg_hrsr_books"},{"rank":4,"category":"Happiness Self-Help","url":"https://www.amazon.com/gp/bestsellers/books/4739/ref=pd_zg_hrsr_books"},{"rank":6,"category":"Philosophy (Books)","url":"https://www.amazon.com/gp/bestsellers/books/11019/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book thought-provoking and life-changing, with a well-written style that makes it an easy one- or two-sitting read. They appreciate its simplicity and practicality in helping readers find their purpose, while also providing good advice about maintaining a healthy lifestyle. The book serves as an excellent introduction to the concept of ikigai, with one customer noting its effectiveness in staying active into old age.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book enjoyable and thought-provoking, describing it as a life-changer.","reviews":["This a great book. This book help me understand what it has to do with life and purpose. It also show me about eating and living life to the fullest....","Great read! Key to happiness in life. Learn to find your Ikigai. Live in the present and not worry about future.","A good read. I am drawn to the concept of Ikigai. Japanese concepts rock! The writing could have been more powerful though!"]},{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as a light and quick read that can be completed in one or two sittings. One customer mentions that the audible version enhances the reading experience.","reviews":["Ikigai is an easy read, with simple concepts to follow for a meaningful life. It is ideal for people seeking purpose in their lives.","Easy to read, applicable to real life in real time. Something anyone can connect with and apply to their lifestyle. It is never too late to change....","...Pros: quick read, good general life principles Cons: not enough emphasis on ikigai, most of the same content is found in other self help books"]},{"name":"Simplicity","sentiment":"positive","text":"Customers appreciate the simplicity of the book, finding it easy to read and understand, with one customer noting that happiness can be really simple.","reviews":["...for three years and saw first hand how people live—so carefree and simple....","...I can''t say if this lifestyle concept is easy to follow, but give it a try and see for yourself.","...Quick, easy and informative read!"]},{"name":"Practical","sentiment":"positive","text":"Customers find the book practical and great for finding purpose, with one customer noting it can be directly applied to life.","reviews":["...What sets Ikigai apart is its practical and actionable approach to finding fulfillment....","I enjoyed reading this book and found it very helpful!","Simple and so smart book. Read it in a one breath. So wise and helpful."]},{"name":"Health","sentiment":"positive","text":"Customers find the book provides good advice for maintaining a healthy lifestyle, including gentle exercises and tips for clearing up one''s life, with one customer noting its benefits for living in the moment.","reviews":["...to follow many of the clearly explained suggestions for a long and healthy life, coming from the longest living community on Earth....","...books I’m studying regarding practical ways to live happier, healthier, and longer....","LEARNING TO LIVE BY THIS BOOK.. GREAT TIPS FOR CLEARING UP YOUR LIFE, OF DETOXING FROM OWNING TOO MUCH.. NOT BEING IN PEACE.."]},{"name":"Lifespan","sentiment":"positive","text":"Customers appreciate the book''s focus on living a long life, with one customer highlighting the importance of staying active into old age, while another mentions the concept of antifragility.","reviews":["...concepts like Stoicism, Buddhism, Logotherapy, Flow, well-being, and longevity. But really, it reads like an amalgamation of concepts....","...information and a wealth of suggestions on how to lead a long and productive life, based on people in Japan who were 100+.","...Be happy, stay active, find purpose, and eat healthy pretty much sums up the whole book. Something to read when you have a few hours to kill."]},{"name":"Generality","sentiment":"positive","text":"Customers find the book excellent as an introduction to ikigai, with one customer noting that it makes sense with each page and provides easy-to-follow advice.","reviews":["Loved reading this book. Simple, easy to follow advice for living a happier, healthy life. Easy to follow and an engaging read.","...In a simple and clear way explains how you can yourself adopt the same lifestyle, with pointers to more in depth information on the diverse...","...Just like any other self help book it is not a step by step guide but more of a way to re-center your thoughts and focus on what is most important..."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, describing it as very well written with simple concepts beautifully expressed.","reviews":["I''ve read this book in Spanish, is well written and got many advices for a having a healthier life....","Beautiful book.......beautifully written.","simple concepts beautiful written, the Japanese know how to live correctly and this little book expresses that."]}],"features":[]}'::jsonb, NULL),
  ('The Subtle Art of Not Giving a F*ck: A Counterintuitive Approach to Living a Good Life', 'Mark Manson', 'https://m.media-amazon.com/images/I/71QKQ9mwV7L._SL1500_.jpg', 'Alternate cover edition of ISBN 9780062457738 In this generation-defining self-help guide, a superstar blogger cuts through the crap to show us how to stop trying to be "positive" all the time so that we can truly become better, happier people. For decades, we’ve been told that positive thinking is the key to a happy, rich life. "F**k positivity," Mark Manson says. "Let’s be honest, shit is f**ked and we have to live with it." In his wildly popular Internet blog, Manson doesn’t sugarcoat or equivocate. He tells it like it is—a dose of raw, refreshing, honest truth that is sorely lacking today. The Subtle Art of Not Giving a F**k is his antidote to the coddling, let’s-all-feel-good mindset that has infected American society and spoiled a generation, rewarding them with gold medals just for showing up. Manson makes the argument, backed both by academic research and well-timed poop jokes, that improving our lives hinges not on our ability to turn lemons into lemonade, but on learning to s', 'Self-help', 212, '9798804636129', '{"title":"The Subtle Art of Not Giving a F*ck: A Counterintuitive Approach to Living a Good Life","author":"Mark Manson","description":"#1 New York Times Bestseller • More than 10 million Copies Sold\nIn this generation-defining self-help guide, a superstar blogger cuts through the crap to show us how to stop trying to be \"positive\" all the time so that we can truly become better, happier people.\nFor decades, we’ve been told that positive thinking is the key to a happy, rich life. \"F**k positivity,\" Mark Manson says. \"Let’s be honest, shit is f**ked and we have to live with it.\" In his wildly popular Internet blog, Manson doesn’t sugarcoat or equivocate. He tells it like it is—a dose of raw, refreshing, honest truth that is sorely lacking today. The Subtle Art of Not Giving a F**k is his antidote to the coddling, let’s-all-feel-good mindset that has infected modern society and spoiled a generation, rewarding them with gold medals just for showing up.\nManson makes the argument, backed both by academic research and well-timed poop jokes, that improving our lives hinges not on our ability to turn lemons into lemonade, but on learning to stomach lemons better. Human beings are flawed and limited—\"not everybody can be extraordinary, there are winners and losers in society, and some of it is not fair or your fault.\" Manson advises us to get to know our limitations and accept them. Once we embrace our fears, faults, and uncertainties, once we stop running and avoiding and start confronting painful truths, we can begin to find the courage, perseverance, honesty, responsibility, curiosity, and forgiveness we seek.\nThere are only so many things we can give a f**k about so we need to figure out which ones really matter, Manson makes clear. While money is nice, caring about what you do with your life is better, because true wealth is about experience. A much-needed grab-you-by-the-shoulders-and-look-you-in-the-eye moment of real-talk, filled with entertaining stories and profane, ruthless humor, The Subtle Art of Not Giving a F*ck is a refreshing slap for a generation to help them lead contented, grounded lives.","asin":"0062457713","isbn13":"9780062457714","price":"$10.45","listPrice":null,"stars":4.5,"starsBreakdown":{"5star":0.71,"4star":0.19,"3star":0.08,"2star":0.01,"1star":0.01},"reviewsCount":160874,"thumbnailImage":"https://m.media-amazon.com/images/I/71QKQ9mwV7L._SL1500_.jpg","url":"https://www.amazon.com/dp/0062457713","genre":"Happiness","publisher":"Harper","pubDate":"September 13, 2016","language":"English","edition":"2nd Edition","pageCount":224,"bestsellerRanks":[{"rank":129,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Happiness Self-Help","url":"https://www.amazon.com/gp/bestsellers/books/4739/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Personal Time Management","url":"https://www.amazon.com/gp/bestsellers/books/9473326011/ref=pd_zg_hrsr_books"},{"rank":1,"category":"Motivational Self-Help (Books)","url":"https://www.amazon.com/gp/bestsellers/books/4744/ref=pd_zg_hrsr_books"}],"inStockText":"Only 1 left in stock - order soon.  In stock","delivery":"Wednesday, July 8","aiSummary":"Customers find this book meaningful and readable, with excellent reminders of important lessons and straightforward advice. Moreover, they appreciate its entertaining and humorous approach, with one customer noting there''s not a dull moment throughout. Additionally, the writing style receives positive feedback, with customers loving everything the author writes, and they value how it changes their perspective on life.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book meaningful, with one describing it as a no-nonsense approach to living a good life.","reviews":["This is a great book. It drags at times and I think the cursing is over done. I had to power through the back end but I think it was worth the finish.","...The helpful part is putting it all in perspective. This is a good book for when you''re having some trouble, but not if you''re having a severe crisis.","Amazing book! Really solidifies what''s important to care about in life. Made me evaluate what/who drives me to be loving, passionate, and feel alive...."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book very readable and consider it a must-read for anyone.","reviews":["Great read, I think Mark brings in a lot of thought provoking, introspective questions. The book is a little intense but I believe thats the point....","While this book wasn''t going to be life-changing, it is a good read and provides some subtle differences about the way you think about things that...","Easy read and very thought provoking. I would recommend this book. I felt like i could hear the authors own inner thoughts as he told his story."]},{"name":"Insightful","sentiment":"positive","text":"Customers find the book insightful, providing excellent reminders of important lessons and offering a fresh perspective on life.","reviews":["So very. insightful, this really reminds the reader to take a different approach to the things that stress us out and helping with how to choose...","Great well written, articulate, deep, simple, humble language, thought provoking, interesting, very good,highly reccomemd, six more word and herd we...","Very insightful, honest and to the point. This book will challenge you to think outside the box, and question yourself & your life as you know it."]},{"name":"Practical","sentiment":"positive","text":"Customers find the book practical, describing it as an excellent self-help book with solid, straightforward advice.","reviews":["...I found his philosophy to be practical and helpful and I recommend his book, particularly as an antidote to depression.","The book gave me some good advice and relief from my mental struggle. Plenty personal lessons could be drawn from the book....","This book is 100% worth the read! Great advice while not being boing or inaccessible. A must read book that is very thought provoking"]},{"name":"Entertaining","sentiment":"positive","text":"Customers find the book entertaining and engaging, describing it as a lighthearted read.","reviews":["...but some of the ways he illustrates it are unique and entertaining. A good kick in the pants to be self- reflective and take charge. I recommend it!","I agree with most of his views, it’s interesting and inspiring to read your thoughts out loud or to be introduced to many of the truths in this book...","Thought provoking, great read, relatable parables and fun. Well worth the read, after I read the ebook I bought the paper back as it was that good."]},{"name":"Humor","sentiment":"positive","text":"Customers find the book humorous, appreciating its witty writing style and the author''s use of sarcasm.","reviews":["This was exactly what I needed to hear in my current life situation. Funny and witty yet very helpful in teaching me what “not” to focus on to keep...","This book was hilarious and insightful. The blunt delivery is very effective. I highlighted many sections of this book to come back to later.","This book was affiming, humorous, well written, and fun to read. Filled with the kind of things most of us wish we had known about when we were young."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, with one customer noting that the author doesn''t sugarcoat anything and writes from the heart.","reviews":["This book was affiming, humorous, well written, and fun to read. Filled with the kind of things most of us wish we had known about when we were young.","...I laughed and almost cried a bit at points, due to the very well written and deep life experience anecdotes from the author that help reinforce the...","...great books he seems to be a fantastic writer. I just released a new book of my own today called the elevator was broken so I took the steps...."]},{"name":"Perspective","sentiment":"positive","text":"Customers appreciate the book''s perspective, describing it as an eye-opening view that changes their outlook on life.","reviews":["...This book can absolutely be eye opening. It just got to the point to where I felt like I was reading the same thing, but a different scenario....","His interesting perspective helped me through a challenging time. He has an amazing way of giving examples for you to visualize his insights....","This book was very eye opening. I learned a lot about myself while reading this and I will definitely recommend to others. Simply amazing."]}],"features":[]}'::jsonb, '{"title":"The Subtle Art of Not Giving a F*ck: A Counterintuitive Approach to Living a Good Life","author":"Mark Manson","description":"Alternate cover edition of ISBN 9780062457738 In this generation-defining self-help guide, a superstar blogger cuts through the crap to show us how to stop trying to be \"positive\" all the time so that we can truly become better, happier people. For decades, we’ve been told that positive thinking is the key to a happy, rich life. \"F**k positivity,\" Mark Manson says. \"Let’s be honest, shit is f**ked and we have to live with it.\" In his wildly popular Internet blog, Manson doesn’t sugarcoat or equivocate. He tells it like it is—a dose of raw, refreshing, honest truth that is sorely lacking today. The Subtle Art of Not Giving a F**k is his antidote to the coddling, let’s-all-feel-good mindset that has infected American society and spoiled a generation, rewarding them with gold medals just for showing up. Manson makes the argument, backed both by academic research and well-timed poop jokes, that improving our lives hinges not on our ability to turn lemons into lemonade, but on learning to stomach lemons better. Human beings are flawed and limited—\"not everybody can be extraordinary, there are winners and losers in society, and some of it is not fair or your fault.\" Manson advises us to get to know our limitations and accept them. Once we embrace our fears, faults, and uncertainties, once we stop running and avoiding and start confronting painful truths, we can begin to find the courage, perseverance, honesty, responsibility, curiosity, and forgiveness we seek. There are only so many things we can give a f**k about so we need to figure out which ones really matter, Manson makes clear. While money is nice, caring about what you do with your life is better, because true wealth is about experience. A much-needed grab-you-by-the-shoulders-and-look-you-in-the-eye moment of real-talk, filled with entertaining stories and profane, ruthless humor, The Subtle Art of Not Giving a F**k is a refreshing slap for a generation to help them lead contented, grounded lives.","genres":["Nonfiction","Self Help","Psychology","Audiobook","Personal Development","Philosophy","Business","Personal Growth","Mental Health","Book Club"],"averageRating":3.86,"ratingsCount":1461605,"ratingsDistribution":{"1":497720,"2":473150,"3":329221,"4":110074,"5":51440},"pages":212,"isbn13":"9798804636129","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1465761302i/28257707.jpg","publishedAt":"2016-09-13","series":{"name":"Mark Manson Collection","position":"1","url":"https://www.goodreads.com/series/344128-mark-manson-collection"},"awards":[],"url":"https://www.goodreads.com/book/show/28257707-the-subtle-art-of-not-giving-a-f-ck","reviews":[]}'::jsonb),
  ('Shoe Dog: A Memoir by the Creator of Nike', 'Phil Knight', 'https://m.media-amazon.com/images/I/71K6tvri7tL._SL1500_.jpg', 'In this candid and riveting memoir, for the first time ever, Nike founder and CEO Phil Knight shares the inside story of the company’s early days as an intrepid start-up and its evolution into one of the world’s most iconic, game-changing, and profitable brands. In 1962, fresh out of business school, Phil Knight borrowed $50 from his father and created a company with a simple mission: import high-quality, low-cost athletic shoes from Japan. Selling the shoes from the trunk of his lime green Plymouth Valiant, Knight grossed $8,000 his first year. Today, Nike’s annual sales top $30 billion. In an age of startups, Nike is the ne plus ultra of all startups, and the swoosh has become a revolutionary, globe-spanning icon, one of the most ubiquitous and recognizable symbols in the world today. But Knight, the man behind the swoosh, has always remained a mystery. Now, for the first time, in a memoir that is candid, humble, gutsy, and wry, he tells his story, beginning with his crossroads momen', 'Business', 400, '9781501135910', '{"title":"Shoe Dog: A Memoir by the Creator of Nike","author":"Phil Knight","description":"In this instant and tenacious New York Times bestseller, Nike founder and board chairman Phil Knight “offers a rare and revealing look at the notoriously media-shy man behind the swoosh” (Booklist, starred review), illuminating his company’s early days as an intrepid start-up and its evolution into one of the world’s most iconic, game-changing, and profitable brands.Bill Gates named Shoe Dog one of his five favorite books of the year and called it “an amazing tale, a refreshingly honest reminder of what the path to business success really looks like. It’s a messy, perilous, and chaotic journey, riddled with mistakes, endless struggles, and sacrifice. Phil Knight opens up in ways few CEOs are willing to do.”  Fresh out of business school, Phil Knight borrowed fifty dollars from his father and launched a company with one simple mission: import high-quality, low-cost running shoes from Japan. Selling the shoes from the trunk of his car in 1963, Knight grossed eight thousand dollars that first year. Today, Nike’s annual sales top $30 billion. In this age of start-ups, Knight’s Nike is the gold standard, and its swoosh is one of the few icons instantly recognized in every corner of the world.  But Knight, the man behind the swoosh, has always been a mystery. In Shoe Dog, he tells his story at last. At twenty-four, Knight decides that rather than work for a big corporation, he will create something all his own, new, dynamic, different. He details the many risks he encountered, the crushing setbacks, the ruthless competitors and hostile bankers—as well as his many thrilling triumphs. Above all, he recalls the relationships that formed the heart and soul of Nike, with his former track coach, the irascible and charismatic Bill Bowerman, and with his first employees, a ragtag group of misfits and savants who quickly became a band of swoosh-crazed brothers.  Together, harnessing the electrifying power of a bold vision and a shared belief in the transformative power of sports, they created a brand—and a culture—that changed everything.","asin":"1501135929","isbn13":"9781501135927","price":"$11.29","listPrice":null,"stars":4.7,"starsBreakdown":{"5star":0.81,"4star":0.16,"3star":0.03,"2star":0,"1star":0},"reviewsCount":63262,"thumbnailImage":"https://m.media-amazon.com/images/I/71K6tvri7tL._SL1500_.jpg","url":"https://www.amazon.com/dp/1501135929","genre":"Fashion & Textile","publisher":"Scribner","pubDate":"May 1, 2018","language":"English","edition":"Reprint","pageCount":400,"bestsellerRanks":[{"rank":474671,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Fashion & Textile Business","url":"https://www.amazon.com/gp/bestsellers/books/3568199011/ref=pd_zg_hrsr_books"},{"rank":2,"category":"Running & Jogging (Books)","url":"https://www.amazon.com/gp/bestsellers/books/16587/ref=pd_zg_hrsr_books"},{"rank":6,"category":"Company Business Profiles (Books)","url":"https://www.amazon.com/gp/bestsellers/books/2542/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  Only 1 left in stock - order soon.","delivery":"Thursday, July 2","aiSummary":"Customers find this memoir engaging and well-written, with a conversational style that keeps them engaged. The book tells an inspiring story of hard work and never giving up, while being incredibly heartfelt and honest. Customers appreciate its entrepreneurial insights, with one noting how it reveals the challenges and stresses of building an innovative company. They enjoy the humor throughout the book, with many mentioning they laugh out loud while reading it.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find this memoir engaging and entertaining, describing it as a great business book.","reviews":["Loved and was completely immersed in the book! A great book to know about the history of this great success story that is NIKE and lot of learnings...","Interesting and inspiring. A nonfiction book that is difficult to put down. This book shows that hard work and devotion to an idea is worthwhile.","i love it ! Well written,interesting ,informative.and inspirational. One of my favorite books to date. I would give it 6 stars if possible"]},{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as an incredible and fascinating read that is well worth the time.","reviews":["Great read to understand how Nike came about. Good insight into grit and perseverance and what it takes to push an idea into a rep and final product....","Good read and I learned a lot about the origin of Nike but found it glaring author highlighting relationship with Jordan but not much on how his...","Engaging story telling, easy read, great history of the entrepreneurial struggles of early Nike... the only thing missing was a mention of my mother-..."]},{"name":"Story","sentiment":"positive","text":"Customers find the book''s story engaging, describing it as an inspiring tale of hard work and determination, with one customer noting it''s a fantastic account of Nike''s history.","reviews":["What a great story! I am not a big reader but this book held my attention and I did not want it to end. Thanks Mr. Knight for sharing your story!","...This book instantly put me into overdrive, motivation overload. Amazing story, amazing life. Knight was the chosen one. Bravo!","...I feel like I was a part of the original Nike team. Fascinating story. Mr. Knight has reassured my own journey and calling of creating COURAJ.com...."]},{"name":"Writing quality","sentiment":"positive","text":"Customers praise the writing style of the memoir, noting its conversational tone and how it kept them engaged.","reviews":["Amazing and well written. Knight has a humility to admit that he worked through panic attacks and near bankruptcy throughout the early years of Nike....","Very well written. A very interesting read with a lot of true factual information some of it of a personal nature. I highly recommend this book.","Beautifully written. Wonderfully funny. So heartfelt. Truly interesting and not what I expected. About life, love and a very small touch of business...."]},{"name":"Emotional","sentiment":"positive","text":"Customers find the book emotionally engaging, describing it as incredibly heartfelt and told from the heart, with the final few chapters being particularly moving.","reviews":["A great story told with humility. Passion. Humanity. And humor. The book is structured in a way that makes it enjoyable to read....","...This book was inspirational and touching. You do not need a background in business or a strong understanding of business to enjoy this book....","...has everything - intrigue, inspiration, business advice, sage wisdom, love, competition and wonderful writing, then read this book...."]},{"name":"Honesty","sentiment":"positive","text":"Customers appreciate the book''s honesty, describing it as an unflinchingly authentic account of life and business.","reviews":["Great read! I couldn''t put it down. It''s a an honest and candid memoir of personal and professional struggles in chasing a dream and building a...","Just what I needed right now. Vulnerable, funny, and real. Find yourself as Phil finds himself. A pure joy to read! Thank you PK","...And, I appreciated the rawness, the honesty, the mistakes that are not ignored, but integrated into the journey, because no one lives a life free of..."]},{"name":"Entrepreneurial","sentiment":"positive","text":"Customers appreciate the book''s entrepreneurial insights, describing it as an incredibly satisfying journey that combines business fortitude and ingenuity. One customer notes how it reveals the challenges and stresses of building an innovative company.","reviews":["...anyone interested in business, sports, personal introspection, entrepreneurship and history. I was de vaster when I finished it...","...but, shoe Dog a compelling story about relationships, entrepreneurial spirit and the guts of a growth business....","...humble that it make you think that''s easy but of course he''s a great businessman with a great vision of the future."]},{"name":"Humor","sentiment":"positive","text":"Customers enjoy the book''s humor, finding it a fascinating story told with wit and charm that makes them laugh out loud.","reviews":["Funny and inspiration. it''s a captivating read. Great for entrepreneurs and those with a dream. Now I want to visit Nike headquarters in Oregon.","Likely the best biography I''ve read. Knight is self effacing, honest, witty and without ego - the anti CEO prototype....","A nice read by the founder of Nike. And humorous despite all the travails of getting the company up and running"]}],"features":[]}'::jsonb, '{"title":"Shoe Dog: A Memoir by the Creator of Nike","author":"Phil Knight","description":"In this candid and riveting memoir, for the first time ever, Nike founder and CEO Phil Knight shares the inside story of the company’s early days as an intrepid start-up and its evolution into one of the world’s most iconic, game-changing, and profitable brands. In 1962, fresh out of business school, Phil Knight borrowed $50 from his father and created a company with a simple mission: import high-quality, low-cost athletic shoes from Japan. Selling the shoes from the trunk of his lime green Plymouth Valiant, Knight grossed $8,000 his first year. Today, Nike’s annual sales top $30 billion. In an age of startups, Nike is the ne plus ultra of all startups, and the swoosh has become a revolutionary, globe-spanning icon, one of the most ubiquitous and recognizable symbols in the world today. But Knight, the man behind the swoosh, has always remained a mystery. Now, for the first time, in a memoir that is candid, humble, gutsy, and wry, he tells his story, beginning with his crossroads moment. At 24, after backpacking around the world, he decided to take the unconventional path, to start his own business—a business that would be dynamic, different. Knight details the many risks and daunting setbacks that stood between him and his dream—along with his early triumphs. Above all, he recalls the formative relationships with his first partners and employees, a ragtag group of misfits and seekers who became a tight-knit band of brothers. Together, harnessing the transcendent power of a shared mission, and a deep belief in the spirit of sport, they built a brand that changed everything.","genres":["Business","Biography","Nonfiction","Memoir","Audiobook","Sports","Autobiography","Entrepreneurship","Biography Memoir","Leadership"],"averageRating":4.45,"ratingsCount":382588,"ratingsDistribution":{"1":231347,"2":108642,"3":31271,"4":7007,"5":4321},"pages":400,"isbn13":"9781501135910","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1457284880i/27220736.jpg","publishedAt":"2016-04-26","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/27220736-shoe-dog","reviews":[]}'::jsonb),
  ('A Brief History of Time', 'Stephen W. Hawking', 'https://m.media-amazon.com/images/I/91ebghaV-eL._SL1500_.jpg', 'A landmark volume in science writing by one of the great minds of our time, Stephen Hawking’s book explores such profound questions as: How did the universe begin—and what made its start possible? Does time always flow forward? Is the universe unending—or are there boundaries? Are there other dimensions in space? What will happen when it all ends? Told in language we all can understand, A Brief History of Time plunges into the exotic realms of black holes and quarks, of antimatter and “arrows of time,” of the big bang and a bigger God—where the possibilities are wondrous and unexpected. With exciting images and profound imagination, Stephen Hawking brings us closer to the ultimate secrets at the very heart of creation.', 'Science', 226, '9780553380163', '{"title":"A Brief History of Time","author":"Stephen Hawking","description":"#1 NEW YORK TIMES BESTSELLERA landmark volume in science writing by one of the great minds of our time, Stephen Hawking’s book explores such profound questions as: How did the universe begin—and what made its start possible? Does time always flow forward? Is the universe unending—or are there boundaries? Are there other dimensions in space? What will happen when it all ends?Told in language we all can understand, A Brief History of Time plunges into the exotic realms of black holes and quarks, of antimatter and “arrows of time,” of the big bang and a bigger God—where the possibilities are wondrous and unexpected. With exciting images and profound imagination, Stephen Hawking brings us closer to the ultimate secrets at the very heart of creation.","asin":"0553380168","isbn13":"9780553380163","price":"$9.15","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.71,"4star":0.2,"3star":0.07,"2star":0.01,"1star":0.01},"reviewsCount":11553,"thumbnailImage":"https://m.media-amazon.com/images/I/91ebghaV-eL._SL1500_.jpg","url":"https://www.amazon.com/dp/0553380168","genre":"Astronomy","publisher":"Bantam","pubDate":"September 1, 1998","language":"English","edition":"10th anniversary","pageCount":212,"bestsellerRanks":[{"rank":8997,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":6,"category":"Relativity Physics (Books)","url":"https://www.amazon.com/gp/bestsellers/books/14592/ref=pd_zg_hrsr_books"},{"rank":9,"category":"Cosmology (Books)","url":"https://www.amazon.com/gp/bestsellers/books/13449/ref=pd_zg_hrsr_books"},{"rank":12,"category":"Astronomy (Books)","url":"https://www.amazon.com/gp/bestsellers/books/13443/ref=pd_zg_hrsr_books"}],"inStockText":"Only 9 left in stock - order soon.  In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book entertaining and well-written, appreciating how it makes complex physics accessible to lay readers. The book provides a beautiful walk through the history of physics, with one customer noting its updated view of the universe''s history. Customers find the content thought-provoking, with one mentioning great intellectual leaps within sentences, and they appreciate how it doesn''t dumb down complex ideas. While some find it easy to read and understand, others consider it a challenging read.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book fantastic and interesting, describing it as a classic that is fun to read. One customer notes it''s particularly good for young minds, while another mentions it''s excellent for getting obsessed with science.","reviews":["Great book and a suprisingly easy read. He made the difficult understandable. I would recommend this book to anyone interested in the Universe","Great read! You don''t have to be a physicist to learn about the physics of the universe. A recommended read!","good book, if you like this subject, respect the author, and will read anything to learn more about it...."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book informative and instructive, providing fascinating information in a concise format that helps readers grasp complex concepts.","reviews":["Tough to understand in some places, but very informative in others. I admire Stephen Hawking and am enjoying his book.","insightful","Not as interesting as I figured though informative, very."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, describing it as well and thoughtful, with one customer noting that it makes physics easier to understand.","reviews":["This book is well written and it gave me great perspective. Now I can understand Sheldon Cooper’s dialogue on the TV series “The Big Bang Theory”....","Hawkins is an excellent writer and allows the average person not versed in physics to understand in basic terms his complicated concepts and ideas.","...It is well-written, but does get very deep and lost me on several occasions. Maybe it''s just me."]},{"name":"Complexity","sentiment":"positive","text":"Customers appreciate how the book explains complex concepts in a simple and straightforward manner, with minimal math involved, making it more accessible than Rovelli''s work.","reviews":["Interesting and detailed discussion of cosmology, quantum mechanics and even some religion and philosophy thrown in....","Simple and pretty easy to follow. It can get dry at times but overall a good read.","a book that was helpful with cosmology and modern physics"]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking, with its fascinating thoughts and brilliant insights that get them thinking about the universe.","reviews":["...While he clearly has brilliant mind he does not forget that some of us do not. He speaks to us all. Everyone should read this at least once.","...for a layman like me to be actually interesting and thought provoking....","Deep thought, from one of the great mans of our time."]},{"name":"Historical context","sentiment":"positive","text":"Customers appreciate the historical context of the book, describing it as a beautiful walk through the history of physics that compiles information about the origins of the universe.","reviews":["A book that does exactly what the titles says; it''s a brief history of time via Hawking''s perspective....","Clear historical background. No real details into the status of physics progress.","...I did learn quite a lot about the various theories of time and space and am glad I read it."]},{"name":"Subject matter","sentiment":"positive","text":"Customers find the book''s subject matter wonderful and appreciate how it puts complex ideas into context. One customer notes that the author does not dumb down the material, while another mentions enjoying the discussion on how discoveries were made.","reviews":["Interesting text,it follows my thoughts concerning the Big Bag Theory and infinity.","Many interesting sections. Also some that were not readable due to lack of understanding technical terms. Skip over those and the book is first rate.","...That said he did a fine job with a massive subject that dictates speaking to complicated theorem and more"]},{"name":"Readability","sentiment":"mixed","text":"Customers have mixed opinions about the book''s readability, with some finding it easy to read and understand, particularly as one of the easiest physics books, while others report it being hard to follow.","reviews":["Excellent book! Easy to understand and grasp the concepts! Amazingly clear to follow this remarkable man''s genius Even for the uneducated in physics!","...Easy to read but do I understand it--no. I am amazed that their are people who work and produce results on things that we cannot see.","...But I must warn you, it is not an easy read for those without prior knowledge in the fundamentals of physics."]}],"features":[]}'::jsonb, '{"title":"A Brief History of Time","author":"Stephen W. Hawking","description":"A landmark volume in science writing by one of the great minds of our time, Stephen Hawking’s book explores such profound questions as: How did the universe begin—and what made its start possible? Does time always flow forward? Is the universe unending—or are there boundaries? Are there other dimensions in space? What will happen when it all ends? Told in language we all can understand, A Brief History of Time plunges into the exotic realms of black holes and quarks, of antimatter and “arrows of time,” of the big bang and a bigger God—where the possibilities are wondrous and unexpected. With exciting images and profound imagination, Stephen Hawking brings us closer to the ultimate secrets at the very heart of creation.","genres":["Science","Nonfiction","Physics","History","Astronomy","Classics","Philosophy","Popular Science","Audiobook","Space"],"averageRating":4.21,"ratingsCount":488641,"ratingsDistribution":{"1":224023,"2":173573,"3":68722,"4":14168,"5":8155},"pages":226,"isbn13":"9780553380163","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1333578746i/3869.jpg","publishedAt":"1998-09-01","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/3869.A_Brief_History_of_Time","reviews":[]}'::jsonb),
  ('Homo Deus: A History of Tomorrow', 'Yuval Noah Harari', 'https://m.media-amazon.com/images/I/71KBDP3mDfL._SL1500_.jpg', 'Yuval Noah Harari, author of the critically-acclaimed New York Times bestseller and international phenomenon Sapiens, returns with an equally original, compelling, and provocative book, turning his focus toward humanity’s future, and our quest to upgrade humans into gods.Over the past century humankind has managed to do the impossible and rein in famine, plague, and war. This may seem hard to accept, but, as Harari explains in his trademark style—thorough, yet riveting—famine, plague and war have been transformed from incomprehensible and uncontrollable forces of nature into manageable challenges. For the first time ever, more people die from eating too much than from eating too little; more people die from old age than from infectious diseases; and more people commit suicide than are killed by soldiers, terrorists and criminals put together. The average American is a thousand times more likely to die from binging at McDonalds than from being blown up by Al Qaeda.What then will replace', 'History', 450, '9780062464316', '{"title":"Homo Deus: A Brief History of Tomorrow ― A NYT Bestselling Popular Science Book on Upgrading Humanity to Godhood","author":"Yuval Noah Harari","description":"Official U.S. edition with full color illustrations throughout.\nNEW YORK TIMES BESTSELLER\nYuval Noah Harari, author of the critically-acclaimed New York Times bestseller and international phenomenon Sapiens, returns with an equally original, compelling, and provocative book, turning his focus toward the future of humanity, and our quest to upgrade humans into gods.\nOver the past century humankind has managed to do the impossible and rein in famine, plague, and war. This may seem hard to accept, but, as Harari explains in his trademark style—thorough, yet riveting—famine, plague and war have been transformed from incomprehensible and uncontrollable forces of nature into manageable challenges. For the first time ever, more people die from eating too much than from eating too little; more people die from old age than from infectious diseases; and more people commit suicide than are killed by soldiers, terrorists and criminals put together. The average American is a thousand times more likely to die from binging at McDonalds than from being blown up by Al Qaeda.\nWhat then will replace famine, plague, and war at the top of the human agenda? As the self-made gods of planet earth, what destinies will we set ourselves, and which quests will we undertake? Homo Deus explores the projects, dreams and nightmares that will shape the twenty-first century—from overcoming death to creating artificial life and artificial intelligence. It asks the fundamental questions: Where do we go from here? And how will we protect this fragile world from our own destructive powers? This provocative work of popular science is the next stage of evolution. This is Homo Deus.\nWith the same insight and clarity that made Sapiens an international hit and a New York Times bestseller, Harari maps out our future.\nBut as we stand on the verge of godhood, what new challenges will replace the old ones?\nThe New Human Agenda: With famine, plague, and war no longer seen as uncontrollable forces of nature, Harari argues that humanity will aim for immortality, happiness, and divinity. What happens when we try to play God?\nThe New Human Agenda: With famine, plague, and war no longer seen as uncontrollable forces of nature, Harari argues that humanity will aim for immortality, happiness, and divinity. What happens when we try to play God?\nUpgrading Humankind: Explore the profound implications of biotechnology and genetic engineering as Homo sapiens attempts to evolve into Homo deus. Is this the next stage of evolution, or the beginning of the end?\nUpgrading Humankind: Explore the profound implications of biotechnology and genetic engineering as Homo sapiens attempts to evolve into Homo deus. Is this the next stage of evolution, or the beginning of the end?\nThe Rise of Dataism: Discover the emergence of a new religion where information is the ultimate value. What happens to human free will when external algorithms know us better than we know ourselves?\nThe Rise of Dataism: Discover the emergence of a new religion where information is the ultimate value. What happens to human free will when external algorithms know us better than we know ourselves?\nThe Future of Consciousness: This groundbreaking book examines the decoupling of intelligence from consciousness and asks the fundamental question: will a world dominated by super-intelligence and AI have any room left for the human spirit?\nThe Future of Consciousness: This groundbreaking book examines the decoupling of intelligence from consciousness and asks the fundamental question: will a world dominated by super-intelligence and AI have any room left for the human spirit?","asin":"0062464310","isbn13":"9780062464316","price":"$17.3","listPrice":null,"stars":4.5,"starsBreakdown":{"5star":0.69,"4star":0.22,"3star":0.07,"2star":0.01,"1star":0.01},"reviewsCount":37887,"thumbnailImage":"https://m.media-amazon.com/images/I/71KBDP3mDfL._SL1500_.jpg","url":"https://www.amazon.com/dp/0062464310","genre":"General","publisher":"Harper","pubDate":"February 21, 2017","language":"English","edition":"Illustrated","pageCount":464,"bestsellerRanks":[{"rank":72721,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":3,"category":"Physics of Time (Books)","url":"https://www.amazon.com/gp/bestsellers/books/14598/ref=pd_zg_hrsr_books"},{"rank":7,"category":"Science Essays & Commentary (Books)","url":"https://www.amazon.com/gp/bestsellers/books/3045861/ref=pd_zg_hrsr_books"},{"rank":8,"category":"History of Civilization & Culture","url":"https://www.amazon.com/gp/bestsellers/books/15812171/ref=pd_zg_hrsr_books"}],"inStockText":"Only 10 left in stock (more on the way).  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this book thought-provoking and informative, with outstanding information and a breadth of knowledge that is astounding. The writing style is highly accessible and written like a good story book, while the historical analysis provides a profound perspective on the past. They appreciate the compelling view of the future and the fascinating ideas presented, with one customer noting how it expands the mind with possibilities.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book engaging and enjoyable, with one customer noting that it makes readers think deeply.","reviews":["Great book, strongly recommend to anyone who hasn’t considered what the future holds in light of the technological advancements we have access to...","This book was a great read and presents a review of history with a view of basic human nature and produces a compelling view of the future in the...","While Sapiens was eye opening, very interesting, and with clear ideas built upon understandable logic, Homo Deus was repetitive, with some ideas..."]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking, providing unexpected insights into the future and human nature.","reviews":["...Thought provoking , even given the poor track record of futuristic projection and if only partially accurate , portends a future leagues unlike the...","Great read. I enjoyed it a lot. Very thought provoking. Highly recommend this to anyone wanting some insight into possible future.","...Harari presents a scientific, insightful, rational, and very meaningful way of looking at our species and how and why we are what we are today, and..."]},{"name":"Informative","sentiment":"positive","text":"Customers find the book informative, praising its outstanding information and fascinating analysis, with one customer noting its astounding breadth of knowledge.","reviews":["...While the writing remained fresh, informative, yet clear in Homo Deus as with Sapiens, the former deals much more with our future than Sapiens did....","Thick with fascinating information.","Comprehensive and in depth reflections on the present and probable future of our species."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, describing it as brilliant, highly accessible, and thought-provoking, with one customer noting it reads like a good story book.","reviews":["...Whether you’re a believer or not, these books are easy to digest, well written and give all of us something to think about.","very well written and an interesting point of view of how AI and the Digital and Information age could lead to Harari''s Homo Deus \"evolution\"...","Harari is a good writer, but I often find the way he forms his arguments in this book to be a bit frustrating...."]},{"name":"Interesting topics","sentiment":"positive","text":"Customers find the book full of fascinating and challenging concepts that stimulate alternate thought and fuel the imagination.","reviews":["Interesting ideas. A bit of a rant and quite repetitious. Could have been outstanding with paring, editing and a good bit of more in-depth thinking.","...Great writing style and very interesting ideas. Recommend reading for those who love thinking about big questions.","...It''s filled with big ideas and theories without the esoteric rhetoric of academic or philosophical writing...."]},{"name":"Storyline","sentiment":"positive","text":"Customers appreciate the storyline of the book, which extrapolates possible futures with compelling logic and presents a very plausible view of mankind''s trajectory.","reviews":["...This is broad based analysis and speculation based on the hard sciences, the humanities, and the social sciences....","Great book, very thought provoking. Harari has an interesting take on the future and is good at getting the reader out of their own heads and...","A good follow up to his first book, Sapiens. He offers a glimpse into the mid to far future of our species...."]},{"name":"Historical","sentiment":"positive","text":"Customers appreciate the book''s historical perspective, with one noting how it grounds speculative ideas with historical precedence.","reviews":["Together with \"Sapience: brief history of humankind\" it will blow your mind out. Highlighted nearly half of the text. Awesome.","...It is a synthesis of history, sociology, science, and philosophy.","...He understands history, evolution and how we came to be who we are and how and why we behave in the manner we do. For me a must read. Frank Dobyns"]},{"name":"Readability","sentiment":"positive","text":"Customers find the book easy to read and follow, with one customer noting it reads like a novel, while another mentions it is accessible to non-technical readers.","reviews":["...Easy to read and worth reading by anyone who cares about where we might be headed as a species because it is filled with relevant information and...","...It is one of the best books of history I’ve read in recent years, clear and insightful....","...Very easy to read and with a good portion of humour."]}],"features":[]}'::jsonb, '{"title":"Homo Deus: A History of Tomorrow","author":"Yuval Noah Harari","description":"Yuval Noah Harari, author of the critically-acclaimed New York Times bestseller and international phenomenon Sapiens, returns with an equally original, compelling, and provocative book, turning his focus toward humanity’s future, and our quest to upgrade humans into gods.Over the past century humankind has managed to do the impossible and rein in famine, plague, and war. This may seem hard to accept, but, as Harari explains in his trademark style—thorough, yet riveting—famine, plague and war have been transformed from incomprehensible and uncontrollable forces of nature into manageable challenges. For the first time ever, more people die from eating too much than from eating too little; more people die from old age than from infectious diseases; and more people commit suicide than are killed by soldiers, terrorists and criminals put together. The average American is a thousand times more likely to die from binging at McDonalds than from being blown up by Al Qaeda.What then will replace famine, plague, and war at the top of the human agenda? As the self-made gods of planet earth, what destinies will we set ourselves, and which quests will we undertake? Homo Deus explores the projects, dreams and nightmares that will shape the twenty-first century—from overcoming death to creating artificial life. It asks the fundamental questions: Where do we go from here? And how will we protect this fragile world from our own destructive powers? This is the next stage of evolution. This is Homo Deus.With the same insight and clarity that made Sapiens an international hit and a New York Times bestseller, Harari maps out our future.","genres":["Nonfiction","History","Science","Philosophy","Audiobook","Anthropology","Sociology","Politics","Psychology","Technology"],"averageRating":4.18,"ratingsCount":293210,"ratingsDistribution":{"1":128988,"2":106303,"3":43478,"4":10447,"5":3994},"pages":450,"isbn13":"","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1468760805i/31138556.jpg","publishedAt":"2017-02-21","series":{"name":"Homo","position":"2","url":"https://www.goodreads.com/series/432659-homo"},"awards":[],"url":"https://www.goodreads.com/book/show/31138556-homo-deus","reviews":[]}'::jsonb),
  ('Range: Why Generalists Triumph in a Specialized World', 'David Epstein', 'https://m.media-amazon.com/images/I/71P+sZn5ctL._SL1500_.jpg', 'Plenty of experts argue that anyone who wants to develop a skill, play an instrument, or lead their field should start early, focus intensely, and rack up as many hours of deliberate practice as possible. If you dabble or delay, you’ll never catch up to the people who got a head start. But a closer look at research on the world’s top performers, from professional athletes to Nobel laureates, shows that early specialization is the exception, not the rule. David Epstein examined the world’s most successful athletes, artists, musicians, inventors, forecasters and scientists. He discovered that in most fields—especially those that are complex and unpredictable—generalists, not specialists, are primed to excel. Generalists often find their path late, and they juggle many interests rather than focusing on one. They’re also more creative, more agile, and able to make connections their more specialized peers can’t see. Provocative, rigorous, and engrossing, Range makes a compelling case for ac', 'Science', 339, '9780735214484', '{"title":"Range: Why Generalists Triumph in a Specialized World","author":"David Epstein","description":"The #1 New York Times bestseller that has all America talking, from the author of the highly anticipated Inside the Box: How Constraints Make Us Better.“The most important business—and parenting—book of the year.” —Forbes“Urgent and important. . . an essential read for bosses, parents, coaches, and anyone who cares about improving performance.” —Daniel H. Pink Shortlisted for the Financial Times/McKinsey Business Book of the Year AwardPlenty of experts argue that anyone who wants to develop a skill, play an instrument, or lead their field should start early, focus intensely, and rack up as many hours of deliberate practice as possible. If you dabble or delay, you’ll never catch up to the people who got a head start. But a closer look at research on the world’s top performers, from professional athletes to Nobel laureates, shows that early specialization is the exception, not the rule. David Epstein examined the world’s most successful athletes, artists, musicians, inventors, forecasters and scientists. He discovered that in most fields—especially those that are complex and unpredictable—generalists, not specialists, are primed to excel. Generalists often find their path late, and they juggle many interests rather than focusing on one. They’re also more creative, more agile, and able to make connections their more specialized peers can’t see. Provocative, rigorous, and engrossing, Range makes a compelling case for actively cultivating inefficiency. Failing a test is the best way to learn. Frequent quitters end up with the most fulfilling careers. The most impactful inventors cross domains rather than deepening their knowledge in a single area. As experts silo themselves further while AI threatens the jobs once reserved for highly focused humans, people who think broadly and embrace diverse experiences and perspectives will increasingly thrive.","asin":"0735214484","isbn13":"9780735214484","price":"$12.19","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.68,"4star":0.23,"3star":0.07,"2star":0.02,"1star":0},"reviewsCount":12770,"thumbnailImage":"https://m.media-amazon.com/images/I/71P+sZn5ctL._SL1500_.jpg","url":"https://www.amazon.com/dp/0735214484","genre":"Developmental Psychology","publisher":"Riverhead Books","pubDate":"May 28, 2019","language":"English","edition":"Illustrated","pageCount":352,"bestsellerRanks":[{"rank":12060,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":1,"category":"Medical Developmental Psychology","url":"https://www.amazon.com/gp/bestsellers/books/6511985011/ref=pd_zg_hrsr_books"},{"rank":3,"category":"Popular Developmental Psychology","url":"https://www.amazon.com/gp/bestsellers/books/11162/ref=pd_zg_hrsr_books"},{"rank":3,"category":"Sports Psychology (Books)","url":"https://www.amazon.com/gp/bestsellers/books/16613/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  Only 1 left in stock - order soon.","delivery":"Thursday, July 2","aiSummary":"Customers find this book to be a must-read for college students, with well-researched examples from various fields and fascinating stories that transform their thinking. The writing style is engaging, and customers appreciate how it explores different areas of study and builds unique skills. They consider the concept innovative, with one customer noting how playful improvisation is key to innovation.","aiKeywords":[{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as a wonderful and joyous read that is great for everyone, particularly noting it as a must-read for college-bound students.","reviews":["Great read. Would definitely recommend. Love the perspective on early speculation vs broad learning and testing of various paths....","Fantastic read that pushes you to really give meaning and thought to the old cliche \"thinking outside of the box\".","...It''s an enjoyable read to anyone who likes history. The book is peppered with fun facts and surprising history of famous people we all know...."]},{"name":"Content","sentiment":"positive","text":"Customers appreciate the book''s content, particularly its anecdotal approach and engaging stories. One customer notes that it is essential reading for everyone.","reviews":["I read Epstein’s the sports gene and that was a great book. Range is limited in its theory and the evidence became repetitive towards the end....","...At times the examples went a tad long, otherwise, it was a good book.","Excellent book. Makes you think. Lots of examples of interesting paths in life. So often the path is unexpected...."]},{"name":"Research","sentiment":"positive","text":"Customers appreciate the extensive research in the book, which includes fascinating anecdotes and data from various fields, with one customer noting how it dispels common \"knowns\" with scientific backing.","reviews":["...I gave it five stars, because it is well written and well researched by someone who has discovered the value of generalization....","This is a very well researched and written book on why it is not only ok but should be preferred to make varieties of experiences....","Love the concept, the case studies and how it’s written. Perhaps it’s longer than needed just to justify the need of having a book"]},{"name":"Thought-provoking","sentiment":"positive","text":"Customers find the book thought-provoking, describing it as truly insightful and transformative to their thinking. One customer particularly appreciates how it emphasizes the value of having breadth of experiences, while another highlights its focus on analogical thinking across disciplines.","reviews":["Really interesting and insightful. Debunks the myth of specialization being the only path to success. Highly recommend it to any and all.","...It''s informative, accurate, thought provoking, and interesting. It''s a fantastic book.","In this thought-provoking book, David Epstein makes a compelling case for the value of being a generalist in a world that often celebrates..."]},{"name":"Examples","sentiment":"positive","text":"Customers appreciate the examples in the book, which help readers explore different areas of study and build unique skills, with one customer noting how knowledge across disciplines fosters breakthroughs.","reviews":["...This is an enlightening book that examines the idea of specialized knowledge....","Full of examples, encourages experimentations and relatively loose creative pursuits. Advocates hard work and curiosity....","This book has great examples and sources for the ways that generalists can succeed where specialists can’t and why...."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, finding it well-argued and easy to follow.","reviews":["...I gave it five stars, because it is well written and well researched by someone who has discovered the value of generalization....","...They are both very well written and both make legitimate points. In fact, there is actually much common ground between the two....","...That aside, this book is well-written and thoroughly researched, and the author’s passion for the subject is evident."]},{"name":"Interesting","sentiment":"positive","text":"Customers find the book fascinating, with each chapter being engaging, and one customer noting that the anecdotes keep it interesting.","reviews":["The stories of some of the most accomplished people in the world are fascinating. Some of them I knew but many were stories I had never heard....","...It''s informative, accurate, thought provoking, and interesting. It''s a fantastic book.","...This is definitely an interesting topic!"]},{"name":"Concept","sentiment":"positive","text":"Customers appreciate the innovative thinking presented in the book, with one customer highlighting how diverse experiences can foster creativity, while another notes that playful improvisation is key to innovation.","reviews":["...He demonstrates how adaptability, creativity, and the ability to connect knowledge across different disciplines can lead to greater innovation and...","Love the concept, the case studies and how it’s written. Perhaps it’s longer than needed just to justify the need of having a book","...book is in the vein of Gladwell’s in that it brings up a lot of interesting ideas and resources to the reader...."]}],"features":[]}'::jsonb, '{"title":"Range: Why Generalists Triumph in a Specialized World","author":"David Epstein","description":"Plenty of experts argue that anyone who wants to develop a skill, play an instrument, or lead their field should start early, focus intensely, and rack up as many hours of deliberate practice as possible. If you dabble or delay, you’ll never catch up to the people who got a head start. But a closer look at research on the world’s top performers, from professional athletes to Nobel laureates, shows that early specialization is the exception, not the rule. David Epstein examined the world’s most successful athletes, artists, musicians, inventors, forecasters and scientists. He discovered that in most fields—especially those that are complex and unpredictable—generalists, not specialists, are primed to excel. Generalists often find their path late, and they juggle many interests rather than focusing on one. They’re also more creative, more agile, and able to make connections their more specialized peers can’t see. Provocative, rigorous, and engrossing, Range makes a compelling case for actively cultivating inefficiency. Failing a test is the best way to learn. Frequent quitters end up with the most fulfilling careers. The most impactful inventors cross domains rather than deepening their knowledge in a single area. As experts silo themselves further while AI threatens the jobs once reserved for highly focused humans, people who think broadly and embrace diverse experiences and perspectives will increasingly thrive.","genres":["Nonfiction","Business","Psychology","Self Help","Audiobook","Science","Personal Development","Education","Leadership","Parenting"],"averageRating":4.13,"ratingsCount":82492,"ratingsDistribution":{"1":32118,"2":32898,"3":14048,"4":2638,"5":790},"pages":339,"isbn13":"9780735214484","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1550048292i/41795733.jpg","publishedAt":"2019-05-28","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/41795733-range","reviews":[]}'::jsonb),
  ('Siddhartha', 'Hermann Hesse', 'https://m.media-amazon.com/images/I/61urry+xagL._SL1200_.jpg', 'Herman Hesse''s classic novel has delighted, inspired, and influenced generations of readers, writers, and thinkers. In this story of a wealthy Indian Brahmin who casts off a life of privilege to seek spiritual fulfillment. Hesse synthesizes disparate philosophies--Eastern religions, Jungian archetypes, Western individualism--into a unique vision of life as expressed through one man''s search for true meaning.', 'Fiction', 152, '9780553208849', '{"title":"Siddhartha: A Novel","author":"Hermann Hesse","description":"The classic novel of a quest for knowledge that has delighted, inspired, and influenced generations of readers, writers, and thinkers—a perennial favorite for graduation gifts.Nominated as one of America’s best-loved novels by PBS’s The Great American ReadThough set in a place and time far removed from the Germany of 1922, the year of the book’s debut, the novel is infused with the sensibilities of Hermann Hesse’s time, synthesizing disparate philosophies–Eastern religions, Jungian archetypes, Western individualism–into a unique vision of life as expressed through one man’s search for meaning. It is the story of the quest of Siddhartha, a wealthy Indian Brahmin who casts off a life of privilege and comfort to seek spiritual fulfillment and wisdom. On his journey, Siddhartha encounters wandering ascetics, Buddhist monks, and successful merchants, as well as a courtesan named Kamala and a simple ferryman who has attained enlightenment. Traveling among these people and experiencing life’s vital passages–love, work, friendship, and fatherhood–Siddhartha discovers that true knowledge is guided from within.","asin":"0553208845","isbn13":"9780553208849","price":"$8.38","listPrice":null,"stars":4.6,"starsBreakdown":{"5star":0.73,"4star":0.18,"3star":0.07,"2star":0.01,"1star":0.01},"reviewsCount":18484,"thumbnailImage":"https://m.media-amazon.com/images/I/61urry+xagL._SL1200_.jpg","url":"https://www.amazon.com/dp/0553208845","genre":"Classics","publisher":"Bantam","pubDate":"January 1, 1982","language":"English","edition":"18th.PRINTING","pageCount":160,"bestsellerRanks":[{"rank":35537,"category":"Books","url":"https://www.amazon.com/gp/bestsellers/books/ref=pd_zg_ts_books"},{"rank":253,"category":"Classic Literature & Fiction","url":"https://www.amazon.com/gp/bestsellers/books/10399/ref=pd_zg_hrsr_books"},{"rank":558,"category":"Religious Literature & Fiction","url":"https://www.amazon.com/gp/bestsellers/books/12489/ref=pd_zg_hrsr_books"},{"rank":835,"category":"Literary Fiction (Books)","url":"https://www.amazon.com/gp/bestsellers/books/10132/ref=pd_zg_hrsr_books"}],"inStockText":"In Stock  In stock","delivery":"Thursday, July 2","aiSummary":"Customers find this novel to be a beautiful read that takes them on a journey through all emotions, with one customer describing it as a poignant heart-wrenching tale. Moreover, the story is a classic tale of a journey to enlightenment, and customers appreciate its breezy readability, with one completing it in just 4 hours. The writing style receives positive feedback for its lyrical quality, and customers consider it a timeless classic. However, the translation quality receives criticism for being full of typos and poor grammar.","aiKeywords":[{"name":"Content","sentiment":"positive","text":"Customers find the book enlightening and meaningful, describing it as a masterpiece.","reviews":["Great book! Great book! This book is amazing, enjoyable, and inspiring. Very fast and east to read. Highly recommended for anyone.","Good book ruined by an outdated translation. This is the 1951 Hilda Rosner translation which was not at all clear from the description or the sample....","...Once you get to the middle, you will start to find it interesting. A great read if your looking for something spiritual...."]},{"name":"Story","sentiment":"positive","text":"Customers appreciate the story of the novel, describing it as a classic tale of a journey to enlightenment and a great narrative about finding self.","reviews":["...Beautiful story, profound and yet simple truths. Everyone should read this book before they graduate from high school!","Great story, but what seems to be a clumsy translation.","a classic tale of course but the KINDLE version here has some very obvious typos that have not been fixed and bad sentences in translation...."]},{"name":"Readability","sentiment":"positive","text":"Customers find the book highly readable, describing it as a breezy and quick fluid read that can be completed in 4 hours.","reviews":["Great book, fairly easy and quick read. Quite a classic. There is a lot of wisdom present in this book....","This was a great and easy read. Very enlightening. It was part of my yoga teacher training but I''m really glad we read it!","Good book & easy to read. Siddhartha is about buddhist philosophy and spiritual enlightenment."]},{"name":"Classic","sentiment":"positive","text":"Customers praise this book as a classic, noting it is a great book of modern times and truly timeless, with one customer specifically mentioning it as a classic of 20th century European literature.","reviews":["...Vivid, beautifully translated and completely honest and timeless. A must read.","A classic and a must for everyone to read several times in life specially when in high school, when becoming a parent, when the kids leave home and...","Classic!"]},{"name":"Entertaining","sentiment":"positive","text":"Customers find the book entertaining, describing it as an awesome adventure and a blissful read.","reviews":["It starts to become more interesting, deep and profound. Incredible the way Hesse put in words the search of the \"Self\" of Buddha.","Great book! Great book! This book is amazing, enjoyable, and inspiring. Very fast and east to read. Highly recommended for anyone.","Impressive narrative, inspirational an entertaining...."]},{"name":"Writing style","sentiment":"positive","text":"Customers appreciate the writing style of the book, describing it as beautifully and fluently written, with one customer noting it follows the style of Buddhist literature.","reviews":["...Blows the covers off the illusion of our existence. Beautifully written and arranged. I will read this again and again.","This book is well written and a journey of the main protagonist all the way towards enlightenment ( I may call this ) with lots of self doubts and...","...The plot has the twists and turns life brings us. The story is beautifully written and has lots to reflect upon, gain insight, and understanding."]},{"name":"Emotional","sentiment":"positive","text":"Customers find the book emotionally engaging, describing it as a poignant and heart-wrenching tale that takes readers on a journey through various feelings.","reviews":["Although written in 1922, Hermann Hesse''s \"Siddhartha\" is still poignant....","...As it was relatable and beautiful to read. Every chapter of Siddhartha''s journey gave insight for anyone to benefit from....","Never has there been a more poignant, emotional and lovely story as Siddhartha. Vivid, beautifully translated and completely honest and timeless...."]},{"name":"Translation quality","sentiment":"negative","text":"Customers criticize the translation of the book, noting numerous typos and awkward phrasing, with one customer specifically mentioning issues with missing words.","reviews":["Despite the copious amount of typos and grammatical errors, this is a gem of a book. I loved Siddharta''s journey toward spritiual oneness...","...It also clearly has not been proofread, with typos and repeat words common every couple pages. The book doesn''t even have page numbers.","...The translation is terrible: it was probably done with some kind of software; it is dry, soulless, and difficult to follow...."]}],"features":[]}'::jsonb, '{"title":"Siddhartha","author":"Hermann Hesse","description":"Herman Hesse''s classic novel has delighted, inspired, and influenced generations of readers, writers, and thinkers. In this story of a wealthy Indian Brahmin who casts off a life of privilege to seek spiritual fulfillment. Hesse synthesizes disparate philosophies--Eastern religions, Jungian archetypes, Western individualism--into a unique vision of life as expressed through one man''s search for true meaning.","genres":["Classics","Fiction","Philosophy","Spirituality","Religion","Literature","Buddhism","German Literature","Novels","Historical Fiction"],"averageRating":4.09,"ratingsCount":901573,"ratingsDistribution":{"1":382161,"2":296150,"3":159651,"4":45737,"5":17874},"pages":152,"isbn13":"","imageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1629378189i/52036.jpg","publishedAt":"1981-12-01","series":null,"awards":[],"url":"https://www.goodreads.com/book/show/52036.Siddhartha","reviews":[]}'::jsonb);
